{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track meals, calories, and nutrition with daily goals and weekly charts",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber'

export type FoodItem = {
  name: string
  calories: number
  categories: FoodCategory[]
}

export type Meal = {
  id: string
  name: string
  items: FoodItem[]
  totalCalories: number
  timestamp: string
  date: string
}

export type MealInput = {
  name: string
  items: FoodItem[]
  timestamp?: string
}

export type DailyGoal = {
  calories: number
  updatedAt: string
}

export type GoalsData = {
  dailyGoal: DailyGoal
}

export type CategoryBreakdown = Record<FoodCategory, number>

export type DailySummary = {
  date: string
  totalCalories: number
  goal: number
  meals: Meal[]
  categoryBreakdown: CategoryBreakdown
  remaining: number
  overGoal: boolean
}

export type DailyBar = {
  date: string
  dayLabel: string
  totalCalories: number
  goal: number
  percentage: number
}

export type WeeklyData = {
  days: DailyBar[]
  maxCalories: number
  goal: number
}

import type { Meal, GoalsData } from './types'

const DATA_DIR = import.meta.dir + '/data'
const MEALS_PATH = `${DATA_DIR}/meals.jsonl`
const GOALS_PATH = `${DATA_DIR}/goals.json`

const DEFAULT_GOALS: GoalsData = {
  dailyGoal: {
    calories: 2000,
    updatedAt: new Date().toISOString(),
  },
}

export const loadMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Meal)
}

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH)
  const exists = await file.exists()
  const line = JSON.stringify(meal) + '\n'

  if (exists) {
    const existing = await file.text()
    await Bun.write(MEALS_PATH, existing + line)
  } else {
    await Bun.write(MEALS_PATH, line)
  }
}

export const deleteMeal = async (mealId: string): Promise<boolean> => {
  const meals = await loadMeals()
  const filtered = meals.filter((m) => m.id !== mealId)
  if (filtered.length === meals.length) return false

  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '')
  await Bun.write(MEALS_PATH, content)
  return true
}

export const loadGoals = async (): Promise<GoalsData> => {
  const file = Bun.file(GOALS_PATH)
  const exists = await file.exists()
  if (!exists) return DEFAULT_GOALS

  const text = await file.text()
  return JSON.parse(text) as GoalsData
}

export const saveGoals = async (goals: GoalsData): Promise<void> => {
  await Bun.write(GOALS_PATH, JSON.stringify(goals, null, 2) + '\n')
}

import type { Meal, MealInput } from './types'
import { appendMeal, deleteMeal, loadMeals } from './data'

const generateId = (): string => crypto.randomUUID()

const toDateString = (iso: string): string => iso.slice(0, 10)

export const logMeal = async (input: MealInput): Promise<Meal> => {
  const timestamp = input.timestamp ?? new Date().toISOString()
  const totalCalories = input.items.reduce((sum, item) => sum + item.calories, 0)

  const meal: Meal = {
    id: generateId(),
    name: input.name,
    items: input.items,
    totalCalories,
    timestamp,
    date: toDateString(timestamp),
  }

  await appendMeal(meal)
  return meal
}

export const removeMeal = async (mealId: string): Promise<boolean> => {
  return deleteMeal(mealId)
}

export const getMealsForDate = async (date: string): Promise<Meal[]> => {
  const meals = await loadMeals()
  return meals.filter((m) => m.date === date)
}

export const getMealsForDateRange = async (startDate: string, endDate: string): Promise<Meal[]> => {
  const meals = await loadMeals()
  return meals.filter((m) => m.date >= startDate && m.date <= endDate)
}

import type { DailyGoal } from './types'
import { loadGoals, saveGoals } from './data'

export const setDailyGoal = async (calories: number): Promise<DailyGoal> => {
  const goals = await loadGoals()
  goals.dailyGoal = {
    calories,
    updatedAt: new Date().toISOString(),
  }
  await saveGoals(goals)
  return goals.dailyGoal
}

export const getDailyGoal = async (): Promise<number> => {
  const goals = await loadGoals()
  return goals.dailyGoal.calories
}

import type { CategoryBreakdown, DailyBar, DailySummary, FoodCategory, Meal, WeeklyData } from './types'
import { getMealsForDate, getMealsForDateRange } from './meals'
import { getDailyGoal } from './goals'

const ALL_CATEGORIES: FoodCategory[] = ['protein', 'carbs', 'fat', 'fiber']

const buildCategoryBreakdown = (meals: Meal[]): CategoryBreakdown => {
  const breakdown: CategoryBreakdown = { protein: 0, carbs: 0, fat: 0, fiber: 0 }

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        breakdown[cat] += item.calories
      }
    }
  }

  return breakdown
}

export const getDailySummary = async (date: string): Promise<DailySummary> => {
  const [meals, goal] = await Promise.all([getMealsForDate(date), getDailyGoal()])
  const totalCalories = meals.reduce((sum, m) => sum + m.totalCalories, 0)
  const categoryBreakdown = buildCategoryBreakdown(meals)

  return {
    date,
    totalCalories,
    goal,
    meals,
    categoryBreakdown,
    remaining: Math.max(0, goal - totalCalories),
    overGoal: totalCalories > goal,
  }
}

const formatDayLabel = (dateStr: string): string => {
  const date = new Date(dateStr + 'T00:00:00')
  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']
  return days[date.getDay()]
}

const getDateNDaysAgo = (n: number, fromDate?: string): string => {
  const base = fromDate ? new Date(fromDate + 'T00:00:00') : new Date()
  base.setDate(base.getDate() - n)
  return base.toISOString().slice(0, 10)
}

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ?? new Date().toISOString().slice(0, 10)
  const start = getDateNDaysAgo(6, end)
  const goal = await getDailyGoal()

  const allMeals = await getMealsForDateRange(start, end)

  const dailyTotals = new Map<string, number>()
  for (const meal of allMeals) {
    dailyTotals.set(meal.date, (dailyTotals.get(meal.date) ?? 0) + meal.totalCalories)
  }

  const days: DailyBar[] = []
  let maxCalories = goal

  for (let i = 6; i >= 0; i--) {
    const date = getDateNDaysAgo(i, end)
    const totalCalories = dailyTotals.get(date) ?? 0
    maxCalories = Math.max(maxCalories, totalCalories)

    days.push({
      date,
      dayLabel: formatDayLabel(date),
      totalCalories,
      goal,
      percentage: 0,
    })
  }

  for (const day of days) {
    day.percentage = maxCalories > 0 ? Math.round((day.totalCalories / maxCalories) * 100) : 0
  }

  return { days, maxCalories, goal }
}

import { h, Fragment } from 'plaited'
import { createSSR } from 'plaited/server'
import type { DailySummary, WeeklyData, FoodCategory } from './types'

const CATEGORY_COLORS: Record<FoodCategory, string> = {
