export const renderDailySummary = (summary: DailySummary): string => {
  const progressPct = Math.min(100, Math.round((summary.totalCalories / summary.goal) * 100))
  const progressColor = summary.overGoal ? OVER_COLOR : BAR_COLOR

  const template = h(
    'div',
    { style: styles.container },
    h('h1', { style: styles.heading }, 'Daily Summary'),
    h('p', { style: { color: MUTED_COLOR, marginBottom: '16px' } }, summary.date),
    h(
      'div',
      { style: styles.card },
      h(
        'div',
        { style: styles.statsRow },
        h('span', {}, `${summary.totalCalories} cal consumed`),
        h('span', {}, `Goal: ${summary.goal} cal`),
      ),
      h(
        'div',
        { style: styles.progressBar },
        h('div', {
          style: {
            width: `${progressPct}%`,
            height: '100%',
            background: progressColor,
            borderRadius: '6px',
            transition: 'width 0.3s ease',
          },
        }),
      ),
      h(
        'div',
        { style: { ...styles.statsRow, marginBottom: '0' } },
        h(
          'span',
          { style: { fontWeight: '600' } },
          summary.overGoal
            ? `Over by ${summary.totalCalories - summary.goal} cal`
            : `${summary.remaining} cal remaining`,
        ),
        h('span', { style: { color: MUTED_COLOR } }, `${progressPct}%`),
      ),
    ),
    // Category breakdown
    h(
      'div',
      { style: styles.card },
      h('h3', { style: { fontSize: '14px', fontWeight: '600', marginBottom: '8px' } }, 'Macro Breakdown'),
      ...(['protein', 'carbs', 'fat', 'fiber'] as FoodCategory[]).map((cat) =>
        h(
          'div',
          {
            style: {
              display: 'flex',
              justifyContent: 'space-between',
              padding: '4px 0',
            },
          },
          h(
            'span',
            {
              style: {
                ...styles.categoryTag,
                background: CATEGORY_COLORS[cat],
              },
            },
            cat,
          ),
          h('span', { style: { fontSize: '14px' } }, `${summary.categoryBreakdown[cat]} cal`),
        ),
      ),
    ),
    // Meals list
    h(
      'div',
      {},
      h('h2', { style: styles.subheading }, 'Meals'),
      ...summary.meals.map((meal) =>
        h(
          'div',
          { style: styles.mealItem },
          h(
            'div',
            { style: { display: 'flex', justifyContent: 'space-between' } },
            h('span', { style: styles.mealName }, meal.name),
            h('span', { style: styles.mealCalories }, `${meal.totalCalories} cal`),
          ),
          h(
            'div',
            { style: { marginTop: '4px' } },
            ...meal.items.map((item) =>
              h(
                'div',
                {
                  style: {
                    fontSize: '13px',
                    color: MUTED_COLOR,
                    padding: '2px 0',
                    display: 'flex',
                    justifyContent: 'space-between',
                  },
                },
                h(
                  'span',
                  {},
                  item.name,
                  ...item.categories.map((cat) =>
                    h(
                      'span',
                      {
                        style: {
                          ...styles.categoryTag,
                          background: CATEGORY_COLORS[cat],
                          fontSize: '9px',
                          padding: '1px 5px',
                        },
                      },
                      cat,
                    ),
                  ),
                ),
                h('span', {}, `${item.calories} cal`),
              ),
            ),
          ),
        ),
      ),
    ),
  )

  const ssr = createSSR()
  return ssr(template)
}

export const renderWeeklyChart = (data: WeeklyData): string => {
  const goalPct = data.maxCalories > 0 ? Math.round((data.goal / data.maxCalories) * 100) : 0
  const goalBottom = `${goalPct}%`

  const template = h(
    'div',
    { style: styles.container },
    h('h1', { style: styles.heading }, 'Weekly Calorie Intake'),
    h(
      'div',
      { style: { ...styles.card, ...styles.chartRelative } },
      // Goal line
      h(
        'div',
        {
          style: {
            ...styles.goalLine,
            bottom: goalBottom,
          },
        },
      ),
      h(
        'span',
        {
          style: {
            ...styles.goalLabel,
            bottom: goalBottom,
          },
        },
        `Goal: ${data.goal}`,
      ),
      // Bars
      h(
        'div',
        { style: styles.chartContainer },
        ...data.days.map((day) => {
          const barHeight = `${day.percentage}%`
          const isOver = day.totalCalories > day.goal
          return h(
            'div',
            { style: styles.barWrapper },
            h('span', { style: styles.barValue }, day.totalCalories > 0 ? `${day.totalCalories}` : ''),
            h('div', {
              style: {
                width: '100%',
                maxWidth: '48px',
                height: barHeight,
                minHeight: day.totalCalories > 0 ? '4px' : '0',
                background: isOver ? OVER_COLOR : BAR_COLOR,
                borderRadius: '6px 6px 0 0',
                transition: 'height 0.3s ease',
              },
            }),
            h('span', { style: styles.barLabel }, day.dayLabel),
            h(
              'span',
              { style: { ...styles.barLabel, fontSize: '9px' } },
              `${day.date.slice(5)}`,
            ),
          )
        }),
      ),
    ),
    // Legend
    h(
      'div',
      {
        style: {
          display: 'flex',
          gap: '16px',
          justifyContent: 'center',
          fontSize: '12px',
          color: MUTED_COLOR,
        },
      },
      h(
        'span',
        { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
        h('span', { style: { width: '12px', height: '12px', background: BAR_COLOR, borderRadius: '2px', display: 'inline-block' } }),
        'Under goal',
      ),
      h(
        'span',
        { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
        h('span', { style: { width: '12px', height: '12px', background: OVER_COLOR, borderRadius: '2px', display: 'inline-block' } }),
        'Over goal',
      ),
      h(
        'span',
        { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
        h('span', { style: { width: '24px', borderTop: `2px dashed ${GOAL_COLOR}`, display: 'inline-block' } }),
        'Daily goal',
      ),
    ),
  )

  const ssr = createSSR()
  return ssr(template)
}

