{
  "name": "@node/expense-logger",
  "version": "1.0.0",
  "description": "Track expenses by category with monthly summaries, pie charts, filtering, and CSV export",
  "modnet": {
    "contentType": "finance",
    "structure": "collection",
    "mechanics": ["filter", "chart", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export const CATEGORIES = [
  'food',
  'transport',
  'housing',
  'entertainment',
  'utilities',
  'other',
] as const

export type Category = (typeof CATEGORIES)[number]

export type Expense = {
  id: string
  amount: number
  category: Category
  date: string // ISO date string YYYY-MM-DD
  notes: string
  createdAt: string // ISO timestamp
}

export type ExpenseInput = {
  amount: number
  category: Category
  date: string
  notes?: string
}

export type DateRange = {
  start?: string
  end?: string
}

export type ExpenseFilter = {
  dateRange?: DateRange
  category?: Category
}

export type CategorySummary = {
  category: Category
  total: number
  percentage: number
  count: number
}

export type MonthlySummary = {
  month: string // YYYY-MM
  total: number
  categories: CategorySummary[]
}

import type { Expense, ExpenseInput, ExpenseFilter } from './types'

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

export const readAllExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

export const appendExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  }
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  const newLine = JSON.stringify(expense) + '\n'
  await Bun.write(DATA_PATH, existing + newLine)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readAllExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  let result = expenses

  if (filter.category) {
    result = result.filter((e) => e.category === filter.category)
  }

  if (filter.dateRange?.start) {
    result = result.filter((e) => e.date >= filter.dateRange!.start!)
  }

  if (filter.dateRange?.end) {
    result = result.filter((e) => e.date <= filter.dateRange!.end!)
  }

  return result
}

import type { Expense, Category, CategorySummary, MonthlySummary } from './types'
import { CATEGORIES } from './types'

export const computeMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))

  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((cat) => {
    const catExpenses = monthExpenses.filter((e) => e.category === cat)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category: cat,
      total: Math.round(catTotal * 100) / 100,
      percentage: total > 0 ? Math.round((catTotal / total) * 1000) / 10 : 0,
      count: catExpenses.length,
    }
  }).filter((c) => c.count > 0)

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)))
  return [...months].sort().reverse()
}

import type { Expense } from './types'

const escapeCsvField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`
  }
  return value
}

export const expensesToCsv = (expenses: Expense[]): string => {
  const header = 'date,amount,category,notes'
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map(
      (e) =>
        `${e.date},${e.amount.toFixed(2)},${e.category},${escapeCsvField(e.notes)}`
    )
  return [header, ...rows].join('\n') + '\n'
}

import type { Category, ExpenseFilter } from './types'
import { CATEGORIES } from './types'
import { readAllExpenses, appendExpense, deleteExpense, filterExpenses } from './store'
import { computeMonthlySummary, getAvailableMonths } from './summary'
import { expensesToCsv } from './export'
import { renderPage } from './ui'

const isCategory = (val: unknown): val is Category =>
  typeof val === 'string' && CATEGORIES.includes(val as Category)

const parseFilter = (url: URL): ExpenseFilter => {
  const category = url.searchParams.get('category')
  const start = url.searchParams.get('start')
  const end = url.searchParams.get('end')

  return {
    category: isCategory(category) ? category : undefined,
    dateRange:
      start || end
        ? { start: start || undefined, end: end || undefined }
        : undefined,
  }
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  // POST /expenses — add a new expense
  if (req.method === 'POST' && url.pathname === '/expenses') {
    const form = await req.formData()
    const amount = parseFloat(form.get('amount') as string)
    const category = form.get('category') as string
    const date = form.get('date') as string
    const notes = (form.get('notes') as string) || ''

    if (isNaN(amount) || amount <= 0) {
      return new Response('Invalid amount', { status: 400 })
    }
    if (!isCategory(category)) {
      return new Response('Invalid category', { status: 400 })
    }
    if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
      return new Response('Invalid date format', { status: 400 })
    }

    await appendExpense({ amount, category, date, notes })
    return Response.redirect(url.origin + '/', 303)
  }

  // POST /expenses/delete — delete an expense
  if (req.method === 'POST' && url.pathname === '/expenses/delete') {
    const form = await req.formData()
    const id = form.get('id') as string
    if (id) await deleteExpense(id)
    return Response.redirect(url.origin + '/', 303)
  }

  // GET /export.csv — export as CSV
  if (req.method === 'GET' && url.pathname === '/export.csv') {
    const allExpenses = await readAllExpenses()
    const filter = parseFilter(url)
    const filtered = filterExpenses(allExpenses, filter)
    const csv = expensesToCsv(filtered)
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv; charset=utf-8',
        'Content-Disposition': 'attachment; filename="expenses.csv"',
      },
    })
  }

  // GET / — main page
  if (req.method === 'GET' && (url.pathname === '/' || url.pathname === '')) {
    const allExpenses = await readAllExpenses()
    const filter = parseFilter(url)
    const filtered = filterExpenses(allExpenses, filter)
    const months = getAvailableMonths(allExpenses)
    const selectedMonth =
      url.searchParams.get('month') || months[0] || new Date().toISOString().slice(0, 7)
    const summary = computeMonthlySummary(allExpenses, selectedMonth)
    const html = renderPage(filtered, summary, filter, months)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  return new Response('Not Found', { status: 404 })
}

