import type { InventoryItem, NewItem, ItemUpdate, BulkImportResult } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const addItem = async (input: NewItem): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((i) => i.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const item: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now(),
    updatedAt: now(),
  }
  items.push(item)
  await writeItems(items)
  return item
}

export const updateItem = async (id: string, update: ItemUpdate): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  if (update.sku) {
    const duplicate = items.find((i) => i.sku === update.sku && i.id !== id)
    if (duplicate) {
      throw new Error(`SKU "${update.sku}" is already in use`)
    }
  }
  items[index] = { ...items[index], ...update, updatedAt: now() }
  await writeItems(items)
  return items[index]
}

export const removeItem = async (id: string): Promise<boolean> => {
  const items = await readItems()
  const filtered = items.filter((i) => i.id !== id)
  if (filtered.length === items.length) return false
  await writeItems(filtered)
  return true
}

export const getItem = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((i) => i.id === id)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((i) => i.sku === sku)
}

export const getAllItems = async (): Promise<InventoryItem[]> => {
  return readItems()
}

export const getLowStock = async (): Promise<InventoryItem[]> => {
  const items = await readItems()
  return items.filter((i) => i.quantity <= i.reorderThreshold)
}

export const search = async (query: string): Promise<InventoryItem[]> => {
  const items = await readItems()
  const q = query.toLowerCase().trim()
  if (!q) return items
  return items.filter(
    (i) => i.name.toLowerCase().includes(q) || i.sku.toLowerCase().includes(q),
  )
}

export const bulkImport = async (newItems: NewItem[]): Promise<BulkImportResult> => {
  const items = await readItems()
  const existingSkus = new Set(items.map((i) => i.sku))
  const result: BulkImportResult = { imported: 0, skipped: 0, errors: [] }

  for (let idx = 0; idx < newItems.length; idx++) {
    const input = newItems[idx]
    if (!input.name || !input.sku) {
      result.errors.push({ index: idx, reason: 'Missing required fields (name, sku)' })
      continue
    }
    if (existingSkus.has(input.sku)) {
      result.skipped++
      result.errors.push({ index: idx, reason: `SKU "${input.sku}" already exists` })
      continue
    }
    const item: InventoryItem = {
      id: generateId(),
      name: input.name,
      sku: input.sku,
      quantity: input.quantity ?? 0,
      category: input.category ?? 'Uncategorized',
      reorderThreshold: input.reorderThreshold ?? 10,
      createdAt: now(),
      updatedAt: now(),
    }
    items.push(item)
    existingSkus.add(input.sku)
    result.imported++
  }

  await writeItems(items)
  return result
}

export const getCategories = async (): Promise<{ name: string; count: number }[]> => {
  const items = await readItems()
  const map = new Map<string, number>()
  for (const item of items) {
    map.set(item.category, (map.get(item.category) ?? 0) + 1)
  }
  return Array.from(map.entries())
    .map(([name, count]) => ({ name, count }))
    .sort((a, b) => b.count - a.count)
}

