export const getDashboardData = async (): Promise<DashboardData> => {
  const [items, lowStockItems, categories] = await Promise.all([
    getAllItems(),
    getLowStock(),
    getCategories(),
  ])
  const totalQuantity = items.reduce((sum, i) => sum + i.quantity, 0)
  return {
    totalItems: items.length,
    totalQuantity,
    lowStockItems,
    categories,
  }
}

export const renderDashboardView = async () => {
  const data = await getDashboardData()
  return renderDashboard(data)
}

export const renderFullView = async () => {
  const [data, items] = await Promise.all([
    getDashboardData(),
    getAllItems(),
  ])
  return renderFullPage(data, items)
}

export const searchItems = async (query: string) => {
  const items = await search(query)
  return renderSearchResults({ items, query, total: items.length })
}

export const importFromJson = async (jsonString: string) => {
  const parsed: NewItem[] = JSON.parse(jsonString)
  if (!Array.isArray(parsed)) {
    throw new Error('JSON must be an array of items')
  }
  const result = await bulkImport(parsed)
  return { result, html: renderImportResult(result) }
}

export const importFromFile = async (filePath: string) => {
  const file = Bun.file(filePath)
  const text = await file.text()
  return importFromJson(text)
}

