  return text.trim() ? JSON.parse(text) : []
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? '',
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const removeBook = async (id: string): Promise<boolean> => {
  const books = await loadBooks()
  const index = books.findIndex((b) => b.id === id)
  if (index === -1) return false
  books.splice(index, 1)
  await saveBooks(books)
  return true
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null

  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount))

  if (book.currentPage === book.pageCount) {
    book.status = 'completed'
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }

  await saveBooks(books)
  return book
}

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null

  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  } else if (status === 'want-to-read') {
    book.currentPage = 0
    book.dateCompleted = null
  } else {
    book.dateCompleted = null
  }

  await saveBooks(books)
  return book
}

export const filterBooks = (books: Book[], options: FilterOptions): Book[] => {
  let filtered = books
  if (options.status) {
    filtered = filtered.filter((b) => b.status === options.status)
  }
  if (options.genre) {
    filtered = filtered.filter((b) => b.genre.toLowerCase() === options.genre!.toLowerCase())
  }
  return filtered
}

export const getGenres = (books: Book[]): string[] => {
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

export const getStats = (books: Book[]): ReadingStats => {
  const completed = books.filter((b) => b.status === 'completed')
  const reading = books.filter((b) => b.status === 'reading')
  const wantToRead = books.filter((b) => b.status === 'want-to-read')

  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) /
        books.length
      : 0

  return {
    totalBooks: books.length,
    booksCompleted: completed.length,
    booksReading: reading.length,
    booksWantToRead: wantToRead.length,
    totalPagesRead,
    averageProgress: Math.round(averageProgress * 100),
  }
}

import { createSSR } from 'plaited'
import type { BookInput, FilterOptions, ReadingStatus } from './types'
import { addBook, filterBooks, getGenres, getStats, loadBooks, removeBook, updateProgress, updateStatus } from './data'
import { renderPage } from './render'

export type { Book, BookInput, FilterOptions, ReadingStats, ReadingStatus } from './types'

export const add = async (input: BookInput) => {
  if (!input.title?.trim()) throw new Error('Title is required')
  if (!input.author?.trim()) throw new Error('Author is required')
  if (!input.genre?.trim()) throw new Error('Genre is required')
  if (!input.pageCount || input.pageCount < 1) throw new Error('Page count must be at least 1')
  return addBook(input)
}

export const remove = async (id: string) => {
  const removed = await removeBook(id)
  if (!removed) throw new Error(`Book not found: ${id}`)
  return { success: true }
}

export const setProgress = async (id: string, currentPage: number) => {
  if (currentPage < 0) throw new Error('Page number cannot be negative')
  const book = await updateProgress(id, currentPage)
  if (!book) throw new Error(`Book not found: ${id}`)
  return book
}

export const setStatus = async (id: string, status: ReadingStatus) => {
  const validStatuses: ReadingStatus[] = ['want-to-read', 'reading', 'completed']
  if (!validStatuses.includes(status)) throw new Error(`Invalid status: ${status}`)
  const book = await updateStatus(id, status)
  if (!book) throw new Error(`Book not found: ${id}`)
  return book
}

export const list = async (filters: FilterOptions = {}) => {
  const books = await loadBooks()
  const filtered = filterBooks(books, filters)
  const stats = getStats(books)
  const genres = getGenres(books)
  return { books: filtered, stats, genres }
}

export const render = async (filters: FilterOptions = {}) => {
  const books = await loadBooks()
  const filtered = filterBooks(books, filters)
  const stats = getStats(books)
  const genres = getGenres(books)
  const template = renderPage(books, filtered, stats, genres, filters)
  const ssr = createSSR()
  return ssr(template)
}

