};

import { BskyAgent } from "@atproto/api";
import type { Credentials, SessionData } from "./types";

const SESSION_PATH = "data/session.json";

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2));
};

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH);
  if (!(await file.exists())) return null;
  try {
    return (await file.json()) as SessionData;
  } catch {
    return null;
  }
};

export const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH);
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, "{}");
  }
};

export const authenticate = async (
  agent: BskyAgent,
  credentials: Credentials
): Promise<SessionData> => {
  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  });

  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  };

  await saveSession(session);
  return session;
};

export const resumeSession = async (
  agent: BskyAgent
): Promise<SessionData | null> => {
  const session = await loadSession();
  if (!session) return null;

  try {
    await agent.resumeSession({
      did: session.did,
      handle: session.handle,
      accessJwt: session.accessJwt,
      refreshJwt: session.refreshJwt,
      active: true,
    });
    return session;
  } catch {
    await clearSession();
    return null;
  }
};

import type { BskyAgent } from "@atproto/api";
import type { PostView, TimelineOptions, TimelineResponse } from "./types";

const toPostView = (item: Record<string, unknown>): PostView => {
  const post = item.post as Record<string, unknown>;
  const author = post.author as Record<string, unknown>;
  const record = post.record as Record<string, unknown>;

  const viewer = (post.viewer as Record<string, unknown>) ?? {};

  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: {
      did: author.did as string,
      handle: author.handle as string,
      displayName: (author.displayName as string) ?? (author.handle as string),
      avatar: author.avatar as string | undefined,
    },
    text: (record.text as string) ?? "",
    createdAt: (record.createdAt as string) ?? "",
    likeCount: (post.likeCount as number) ?? 0,
    repostCount: (post.repostCount as number) ?? 0,
    replyCount: (post.replyCount as number) ?? 0,
    likeUri: viewer.like as string | undefined,
    indexedAt: (post.indexedAt as string) ?? "",
  };
};

export const getTimeline = async (
  agent: BskyAgent,
  options: TimelineOptions = {}
): Promise<TimelineResponse> => {
  const { limit = 25, cursor } = options;

  const response = await agent.getTimeline({
    limit,
    cursor,
  });

  const posts = response.data.feed.map((item) =>
    toPostView(item as unknown as Record<string, unknown>)
  );

  return {
    posts,
    cursor: response.data.cursor,
  };
};

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  options: TimelineOptions = {}
): Promise<TimelineResponse> => {
  const { limit = 25, cursor } = options;

  const response = await agent.getAuthorFeed({
    actor,
    limit,
    cursor,
  });

  const posts = response.data.feed.map((item) =>
    toPostView(item as unknown as Record<string, unknown>)
  );

  return {
    posts,
    cursor: response.data.cursor,
  };
};

import { RichText, type BskyAgent } from "@atproto/api";

export const createPost = async (
  agent: BskyAgent,
  text: string
): Promise<{ uri: string; cid: string }> => {
  const rt = new RichText({ text });
  await rt.detectFacets(agent);

  const response = await agent.post({
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  });

  return { uri: response.uri, cid: response.cid };
};

export const deletePost = async (
  agent: BskyAgent,
  postUri: string
): Promise<void> => {
  await agent.deletePost(postUri);
};

export const likePost = async (
  agent: BskyAgent,
  uri: string,
  cid: string
): Promise<string> => {
  const response = await agent.like(uri, cid);
  return response.uri;
};

export const unlikePost = async (
  agent: BskyAgent,
  likeUri: string
): Promise<void> => {
  await agent.deleteLike(likeUri);
};

export const repost = async (
  agent: BskyAgent,
  uri: string,
  cid: string
): Promise<string> => {
  const response = await agent.repost(uri, cid);
  return response.uri;
};

export const undoRepost = async (
  agent: BskyAgent,
  repostUri: string
): Promise<void> => {
  await agent.deleteRepost(repostUri);
};

import type { BskyAgent } from "@atproto/api";
import type { ProfileView } from "./types";

export const getProfile = async (
  agent: BskyAgent,
  actor: string
): Promise<ProfileView> => {
  const response = await agent.getProfile({ actor });
  const data = response.data;
  const viewer = (data.viewer as Record<string, unknown>) ?? {};

  return {
    did: data.did,
    handle: data.handle,
    displayName: data.displayName ?? data.handle,
    description: data.description ?? "",
    avatar: data.avatar,
    banner: data.banner,
    followersCount: data.followersCount ?? 0,
    followsCount: data.followsCount ?? 0,
    postsCount: data.postsCount ?? 0,
    isFollowing: !!viewer.following,
    followUri: viewer.following as string | undefined,
  };
};

export const follow = async (
  agent: BskyAgent,
  did: string
): Promise<string> => {
  const response = await agent.follow(did);
  return response.uri;
};

export const unfollow = async (
  agent: BskyAgent,
  followUri: string
): Promise<void> => {
  await agent.deleteFollow(followUri);
};

export const searchUsers = async (
  agent: BskyAgent,
  query: string,
  limit = 10
): Promise<ProfileView[]> => {
  const response = await agent.searchActors({
    term: query,
    limit,
  });

  return response.data.actors.map((actor) => {
    const viewer = (actor.viewer as Record<string, unknown>) ?? {};
    return {
      did: actor.did,
      handle: actor.handle,
      displayName: actor.displayName ?? actor.handle,
      description: actor.description ?? "",
      avatar: actor.avatar,
      banner: undefined,
      followersCount: actor.indexedAt ? 0 : 0,
      followsCount: 0,
      postsCount: 0,
      isFollowing: !!viewer.following,
      followUri: viewer.following as string | undefined,
    };
  });
};

