import { authenticate, resumeSession, clearSession } from "./auth";
import { getTimeline, getAuthorFeed } from "./feed";
import { createPost, deletePost, likePost, unlikePost, repost, undoRepost } from "./posts";
import { getProfile, follow, unfollow, searchUsers } from "./profiles";
import type {
  Credentials,
  PostView,
  ProfileView,
  TimelineOptions,
  TimelineResponse,
} from "./types";

export type BlueskyClient = {
  agent: BskyAgent;
  did: string;
  handle: string;
  getTimeline: (options?: TimelineOptions) => Promise<TimelineResponse>;
  getAuthorFeed: (actor: string, options?: TimelineOptions) => Promise<TimelineResponse>;
  createPost: (text: string) => Promise<{ uri: string; cid: string }>;
  deletePost: (postUri: string) => Promise<void>;
  likePost: (uri: string, cid: string) => Promise<string>;
  unlikePost: (likeUri: string) => Promise<void>;
  repost: (uri: string, cid: string) => Promise<string>;
  undoRepost: (repostUri: string) => Promise<void>;
  getProfile: (actor: string) => Promise<ProfileView>;
  follow: (did: string) => Promise<string>;
  unfollow: (followUri: string) => Promise<void>;
  searchUsers: (query: string, limit?: number) => Promise<ProfileView[]>;
  logout: () => Promise<void>;
};

export const createBlueskyClient = async (
  credentials?: Credentials
): Promise<BlueskyClient> => {
  const agent = new BskyAgent({
    service: "https://bsky.social",
  });

  let session = await resumeSession(agent);

  if (!session && credentials) {
    session = await authenticate(agent, credentials);
  }

  if (!session) {
    throw new Error(
      "No active session and no credentials provided. Please log in."
    );
  }

  return {
    agent,
    did: session.did,
    handle: session.handle,
    getTimeline: (options?: TimelineOptions) => getTimeline(agent, options),
    getAuthorFeed: (actor: string, options?: TimelineOptions) =>
      getAuthorFeed(agent, actor, options),
    createPost: (text: string) => createPost(agent, text),
    deletePost: (postUri: string) => deletePost(agent, postUri),
    likePost: (uri: string, cid: string) => likePost(agent, uri, cid),
    unlikePost: (likeUri: string) => unlikePost(agent, likeUri),
    repost: (uri: string, cid: string) => repost(agent, uri, cid),
    undoRepost: (repostUri: string) => undoRepost(agent, repostUri),
    getProfile: (actor: string) => getProfile(agent, actor),
    follow: (did: string) => follow(agent, did),
    unfollow: (followUri: string) => unfollow(agent, followUri),
    searchUsers: (query: string, limit?: number) => searchUsers(agent, query, limit),
    logout: () => clearSession(),
  };
};

