// Parses markdown-style bold (**text**) and italic (*text*) into template nodes
export const formatMessageText = (text: string): TemplateObject => {
  const parts: (string | TemplateObject)[] = []
  let remaining = text

  const boldRegex = /\*\*(.+?)\*\*/
  const italicRegex = /(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/

  while (remaining.length > 0) {
    const boldMatch = boldRegex.exec(remaining)
    const italicMatch = italicRegex.exec(remaining)

    let nextMatch: RegExpExecArray | null = null
    let tag: 'strong' | 'em' = 'strong'

    if (boldMatch && italicMatch) {
      if (boldMatch.index <= italicMatch.index) {
        nextMatch = boldMatch
        tag = 'strong'
      } else {
        nextMatch = italicMatch
        tag = 'em'
      }
    } else if (boldMatch) {
      nextMatch = boldMatch
      tag = 'strong'
    } else if (italicMatch) {
      nextMatch = italicMatch
      tag = 'em'
    }

    if (!nextMatch) {
      parts.push(remaining)
      break
    }

    if (nextMatch.index > 0) {
      parts.push(remaining.slice(0, nextMatch.index))
    }

    parts.push(h(tag, {}, nextMatch[1]))
    remaining = remaining.slice(nextMatch.index + nextMatch[0].length)
  }

  return h('span', {}, ...parts)
}

