export const createRoom = async (name: string, description: string, createdBy: string): Promise<Room> => {
  await ensureDataDirs()
  const rooms = await loadRooms()

  const room: Room = {
    id: generateId(),
    name,
    description,
    createdBy,
    createdAt: new Date().toISOString(),
  }

  rooms.push(room)
  await saveRooms(rooms)
  return room
}

export const listRooms = async (): Promise<Room[]> =>
  loadRooms()

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await loadRooms()
  return rooms.find((r) => r.id === roomId)
}

export const listRoomsWithUnread = async (userId: string): Promise<RoomWithUnread[]> => {
  const [rooms, cursors] = await Promise.all([loadRooms(), loadCursors()])
  const userCursors = cursors[userId] ?? {}

  const results: RoomWithUnread[] = await Promise.all(
    rooms.map(async (room) => {
      const messages = await loadMessages(room.id)
      const lastReadId = userCursors[room.id]
      let unreadCount = 0

      if (!lastReadId) {
        unreadCount = messages.length
      } else {
        const lastReadIndex = messages.findIndex((m) => m.id === lastReadId)
        unreadCount = lastReadIndex === -1 ? messages.length : messages.length - lastReadIndex - 1
      }

      return { ...room, unreadCount }
    })
  )

  return results
}

import type { Message } from './types'
import { loadMessages, saveMessages, loadCursors, saveCursors, ensureDataDirs } from './store'

const generateId = (): string =>
  crypto.randomUUID()

export const sendMessage = async (roomId: string, sender: string, text: string): Promise<Message> => {
  await ensureDataDirs()
  const messages = await loadMessages(roomId)

  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  }

  messages.push(message)
  await saveMessages(roomId, messages)
  return message
}

export const getMessages = async (roomId: string, limit?: number): Promise<Message[]> => {
  const messages = await loadMessages(roomId)
  if (limit && limit > 0) {
    return messages.slice(-limit)
  }
  return messages
}

export const markAsRead = async (userId: string, roomId: string): Promise<void> => {
  const [messages, cursors] = await Promise.all([loadMessages(roomId), loadCursors()])
  const lastMessage = messages.at(-1)

  if (lastMessage) {
    if (!cursors[userId]) {
      cursors[userId] = {}
    }
    cursors[userId][roomId] = lastMessage.id
    await saveCursors(cursors)
  }
}

