import type { Thread, Reply, SortMode, VoteDirection } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

const generateId = (): string => crypto.randomUUID()

const readThreads = async (): Promise<Thread[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeThreads = async (threads: Thread[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(threads, null, 2))
}

export const createThread = async (title: string, body: string, author: string): Promise<Thread> => {
  const threads = await readThreads()
  const thread: Thread = {
    id: generateId(),
    title,
    body,
    author,
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
    replies: [],
  }
  threads.push(thread)
  await writeThreads(threads)
  return thread
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const threads = await readThreads()
  return threads.find((t) => t.id === id)
}

export const listThreads = async (sort: SortMode = 'newest', query?: string): Promise<Thread[]> => {
  let threads = await readThreads()

  if (query) {
    const q = query.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(q))
  }

  const scoreOf = (t: Thread): number => t.upvotes - t.downvotes

  switch (sort) {
    case 'newest':
      threads.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      break
    case 'top':
      threads.sort((a, b) => scoreOf(b) - scoreOf(a))
      break
    case 'active':
      threads.sort((a, b) => b.replies.length - a.replies.length)
      break
  }

  return threads
}

export const addReply = async (
  threadId: string,
  body: string,
  author: string,
  parentReplyId?: string,
): Promise<Reply | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  if (parentReplyId) {
    const parent = thread.replies.find((r) => r.id === parentReplyId)
    if (!parent || parent.parentReplyId !== null) return null
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId: parentReplyId ?? null,
    body,
    author,
    createdAt: new Date().toISOString(),
    upvotes: 0,
    downvotes: 0,
  }

  thread.replies.push(reply)
  await writeThreads(threads)
  return reply
}

export const voteThread = async (threadId: string, direction: VoteDirection): Promise<Thread | null> => {
  const threads = await readThreads()
  const thread = threads.find((t) => t.id === threadId)
  if (!thread) return null

  if (direction === 'up') thread.upvotes++
  else thread.downvotes++

  await writeThreads(threads)
  return thread
}

export const voteReply = async (
  replyId: string,
  direction: VoteDirection,
): Promise<Reply | null> => {
  const threads = await readThreads()
  for (const thread of threads) {
    const reply = thread.replies.find((r) => r.id === replyId)
    if (reply) {
      if (direction === 'up') reply.upvotes++
      else reply.downvotes++
      await writeThreads(threads)
      return reply
    }
  }
  return null
}

