const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${typeof v === 'number' ? `${v}px` : v}`)
    .join(';')

const timeAgo = (iso: string): string => {
  const seconds = Math.floor((Date.now() - new Date(iso).getTime()) / 1000)
  if (seconds < 60) return 'just now'
  const minutes = Math.floor(seconds / 60)
  if (minutes < 60) return `${minutes}m ago`
  const hours = Math.floor(minutes / 60)
  if (hours < 24) return `${hours}h ago`
  const days = Math.floor(hours / 24)
  return `${days}d ago`
}

const renderVoteBox = (id: string, upvotes: number, downvotes: number, entityType: 'threads' | 'replies') => {
  const score = upvotes - downvotes
  return h('div', { style: styleToStr(styles.voteBox) },
    h('button', {
      style: styleToStr(styles.voteBtn),
      'p-trigger': `vote-up-${entityType}-${id}`,
      title: 'Upvote',
    }, '\u25B2'),
    h('span', { style: styleToStr(styles.voteScore) }, String(score)),
    h('button', {
      style: styleToStr(styles.voteBtn),
      'p-trigger': `vote-down-${entityType}-${id}`,
      title: 'Downvote',
    }, '\u25BC'),
  )
}

