    h('div', { style: styleToStr(styles.replyContainer) },
      h('h3', { style: 'font-size:16px;font-weight:600;color:#1a1a2e;margin-bottom:12px' },
        `${thread.replies.length} ${thread.replies.length === 1 ? 'Reply' : 'Replies'}`,
      ),
