import { createThread, getThread, listThreads, addReply, voteThread, voteReply } from './store'
import { renderThreadList, renderNewThreadForm, renderThreadDetail, renderNestedReplyForm } from './render'
import type { SortMode, VoteDirection } from './types'

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('application/json')) {
    return req.json()
  }
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((value, key) => {
    result[key] = value
  })
  return result
}

const html = (body: string, status = 200) =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const redirect = (url: string) =>
  new Response(null, { status: 303, headers: { Location: url } })

const server = Bun.serve({
  port: Number(process.env.PORT ?? 3000),
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // -- Pages --

    if (method === 'GET' && pathname === '/') {
      const sort = (url.searchParams.get('sort') ?? 'newest') as SortMode
      const query = url.searchParams.get('q') ?? ''
      const threads = await listThreads(sort, query || undefined)
      return html(renderThreadList(threads, sort, query))
    }

    if (method === 'GET' && pathname === '/new') {
      return html(renderNewThreadForm())
    }

    const threadDetailMatch = pathname.match(/^\/threads\/([^/]+)$/)
    if (method === 'GET' && threadDetailMatch) {
      const thread = await getThread(threadDetailMatch[1])
      if (!thread) return html('<h1>Thread not found</h1>', 404)
      return html(renderThreadDetail(thread))
    }

    const replyFormMatch = pathname.match(/^\/threads\/([^/]+)\/reply$/)
    if (method === 'GET' && replyFormMatch) {
      const thread = await getThread(replyFormMatch[1])
      const parentId = url.searchParams.get('parent') ?? ''
      if (!thread) return html('<h1>Thread not found</h1>', 404)
      return html(renderNestedReplyForm(thread, parentId))
    }

    // -- API: Threads --

    if (method === 'POST' && pathname === '/api/threads') {
      const data = await parseFormData(req)
      const { title, body, author } = data
      if (!title || !body) return json({ error: 'title and body are required' }, 400)
      const thread = await createThread(title, body, author || 'Anonymous')
      const accept = req.headers.get('accept') ?? ''
      if (accept.includes('application/json')) return json(thread, 201)
      return redirect(`/threads/${thread.id}`)
    }

    if (method === 'GET' && pathname === '/api/threads') {
      const sort = (url.searchParams.get('sort') ?? 'newest') as SortMode
      const query = url.searchParams.get('q') ?? undefined
      const threads = await listThreads(sort, query)
      return json(threads)
    }

    // -- API: Replies --

    const repliesMatch = pathname.match(/^\/api\/threads\/([^/]+)\/replies$/)
    if (method === 'POST' && repliesMatch) {
      const threadId = repliesMatch[1]
      const data = await parseFormData(req)
      const { body, author, parentReplyId } = data
      if (!body) return json({ error: 'body is required' }, 400)
      const reply = await addReply(threadId, body, author || 'Anonymous', parentReplyId || undefined)
      if (!reply) return json({ error: 'thread or parent reply not found' }, 404)
      const accept = req.headers.get('accept') ?? ''
      if (accept.includes('application/json')) return json(reply, 201)
      return redirect(`/threads/${threadId}`)
    }

    // -- API: Voting --

    const threadVoteMatch = pathname.match(/^\/api\/threads\/([^/]+)\/vote$/)
    if (method === 'POST' && threadVoteMatch) {
      const data = await parseFormData(req)
      const direction = data.direction as VoteDirection
      if (direction !== 'up' && direction !== 'down') return json({ error: 'direction must be up or down' }, 400)
      const thread = await voteThread(threadVoteMatch[1], direction)
      if (!thread) return json({ error: 'thread not found' }, 404)
      return json(thread)
    }

    const replyVoteMatch = pathname.match(/^\/api\/replies\/([^/]+)\/vote$/)
    if (method === 'POST' && replyVoteMatch) {
      const data = await parseFormData(req)
      const direction = data.direction as VoteDirection
      if (direction !== 'up' && direction !== 'down') return json({ error: 'direction must be up or down' }, 400)
      const reply = await voteReply(replyVoteMatch[1], direction)
      if (!reply) return json({ error: 'reply not found' }, 404)
      return json(reply)
    }

    return html('<h1>404 Not Found</h1>', 404)
  },
})

console.log(`Discussion Forum running at http://localhost:${server.port}`)

