const seededRandom = (seed: number): number => {
  const x = Math.sin(seed) * 10000
  return x - Math.floor(x)
}

const generateCondition = (seed: number) => {
  const idx = Math.floor(seededRandom(seed) * CONDITIONS.length)
  return CONDITIONS[idx]
}

const generateCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const cityInfo = CITY_DATA[key] ?? { lat: 0, lon: 0, country: 'XX', baseTemp: 15 }
  const now = Math.floor(Date.now() / 1000)
  const seed = key.length + now % 1000
  const tempVariation = (seededRandom(seed) - 0.5) * 10
  const temp = cityInfo.baseTemp + tempVariation
  const condition = generateCondition(seed)

  return {
    coord: { lon: cityInfo.lon, lat: cityInfo.lat },
    weather: [condition],
    main: {
      temp: Math.round(temp * 10) / 10,
      feels_like: Math.round((temp - 2 + seededRandom(seed + 1) * 4) * 10) / 10,
      temp_min: Math.round((temp - 3) * 10) / 10,
      temp_max: Math.round((temp + 3) * 10) / 10,
      pressure: 1013 + Math.floor((seededRandom(seed + 2) - 0.5) * 20),
      humidity: 40 + Math.floor(seededRandom(seed + 3) * 50),
    },
    visibility: 8000 + Math.floor(seededRandom(seed + 4) * 2000),
    wind: {
      speed: Math.round((2 + seededRandom(seed + 5) * 10) * 10) / 10,
      deg: Math.floor(seededRandom(seed + 6) * 360),
    },
    clouds: { all: Math.floor(seededRandom(seed + 7) * 100) },
    dt: now,
    sys: {
      country: cityInfo.country,
      sunrise: now - (now % 86400) + 6 * 3600,
      sunset: now - (now % 86400) + 18 * 3600,
    },
    name: city.charAt(0).toUpperCase() + city.slice(1),
  }
}

const generateForecast = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const cityInfo = CITY_DATA[key] ?? { lat: 0, lon: 0, country: 'XX', baseTemp: 15 }
  const now = Math.floor(Date.now() / 1000)
  const startOfDay = now - (now % 86400)

  const list: ForecastEntry[] = []

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 24; hour += 3) {
      const dt = startOfDay + day * 86400 + hour * 3600
      const seed = key.length * 100 + day * 10 + hour
      const dailyVariation = (seededRandom(seed) - 0.5) * 8
      const hourlyVariation = -5 * Math.cos((hour / 24) * 2 * Math.PI)
      const temp = cityInfo.baseTemp + dailyVariation + hourlyVariation
      const condition = generateCondition(seed + day)
      const date = new Date(dt * 1000)
      const dtTxt = `${date.getUTCFullYear()}-${String(date.getUTCMonth() + 1).padStart(2, '0')}-${String(date.getUTCDate()).padStart(2, '0')} ${String(date.getUTCHours()).padStart(2, '0')}:00:00`

      list.push({
        dt,
        main: {
          temp: Math.round(temp * 10) / 10,
          feels_like: Math.round((temp - 1.5) * 10) / 10,
          temp_min: Math.round((temp - 2) * 10) / 10,
          temp_max: Math.round((temp + 2) * 10) / 10,
          pressure: 1013 + Math.floor((seededRandom(seed + 10) - 0.5) * 20),
          humidity: 40 + Math.floor(seededRandom(seed + 11) * 50),
        },
        weather: [condition],
        wind: {
          speed: Math.round((2 + seededRandom(seed + 12) * 10) * 10) / 10,
          deg: Math.floor(seededRandom(seed + 13) * 360),
        },
        dt_txt: dtTxt,
      })
    }
  }

  return {
    city: {
      name: city.charAt(0).toUpperCase() + city.slice(1),
      country: cityInfo.country,
    },
    list,
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const dayMap = new Map<string, ForecastEntry[]>()

  for (const entry of forecast.list) {
    const dateKey = entry.dt_txt.split(' ')[0]
    const existing = dayMap.get(dateKey) ?? []
    existing.push(entry)
    dayMap.set(dateKey, existing)
  }

  const dailies: DayForecast[] = []

  for (const [dateKey, entries] of dayMap) {
    const temps = entries.map((e) => e.main.temp)
    const high = Math.max(...temps)
    const low = Math.min(...temps)
    const midday = entries.find((e) => e.dt_txt.includes('12:00')) ?? entries[Math.floor(entries.length / 2)]
    const date = new Date(dateKey + 'T12:00:00Z')
    const dayName = DAY_NAMES[date.getUTCDay()]

    dailies.push({
      date: dateKey,
      dayName,
      high: Math.round(high * 10) / 10,
      low: Math.round(low * 10) / 10,
      icon: midday.weather[0].icon,
      description: midday.weather[0].description,
    })
  }

  return dailies
}

export const getWeatherIcon = (iconCode: string): string =>
  WEATHER_ICONS[iconCode] ?? '🌡️'

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9 / 5 + 32) * 10) / 10

export const getWeatherData = (city: string): WeatherDashboardData => {
  const current = generateCurrentWeather(city)
  const forecast = generateForecast(city)
  const dailyForecasts = aggregateDailyForecasts(forecast)

  return { current, forecast, dailyForecasts }
}

