import { h } from 'plaited'
import type { DayForecast } from './types'

type ChartPoint = { x: number; y: number }

const SVG_WIDTH = 600
const SVG_HEIGHT = 200
const PADDING = { top: 30, right: 40, bottom: 40, left: 50 }

const chartWidth = SVG_WIDTH - PADDING.left - PADDING.right
const chartHeight = SVG_HEIGHT - PADDING.top - PADDING.bottom

const buildPolyline = (points: ChartPoint[]): string =>
  points.map((p) => `${p.x},${p.y}`).join(' ')

const mapToPoints = (values: number[], minVal: number, maxVal: number): ChartPoint[] => {
  const range = maxVal - minVal || 1
  return values.map((val, i) => ({
    x: PADDING.left + (i / Math.max(values.length - 1, 1)) * chartWidth,
    y: PADDING.top + chartHeight - ((val - minVal) / range) * chartHeight,
  }))
}

export const renderTemperatureChart = (forecasts: DayForecast[]) => {
  const highs = forecasts.map((f) => f.high)
  const lows = forecasts.map((f) => f.low)
  const allTemps = [...highs, ...lows]
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2

  const highPoints = mapToPoints(highs, minTemp, maxTemp)
  const lowPoints = mapToPoints(lows, minTemp, maxTemp)

  const gridLines = []
  const tempRange = maxTemp - minTemp
  const step = Math.ceil(tempRange / 4)
  for (let t = Math.ceil(minTemp); t <= maxTemp; t += step) {
    const y = PADDING.top + chartHeight - ((t - minTemp) / (maxTemp - minTemp)) * chartHeight
    gridLines.push(
      h('line', {
        x1: String(PADDING.left),
        y1: String(Math.round(y)),
        x2: String(SVG_WIDTH - PADDING.right),
        y2: String(Math.round(y)),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(PADDING.left - 8),
        y: String(Math.round(y + 4)),
        'text-anchor': 'end',
        fill: '#888',
        'font-size': '11',
      }, `${t}°`)
    )
  }

  const dayLabels = forecasts.map((f, i) => {
    const x = PADDING.left + (i / Math.max(forecasts.length - 1, 1)) * chartWidth
    return h('text', {
      x: String(Math.round(x)),
      y: String(SVG_HEIGHT - 8),
      'text-anchor': 'middle',
      fill: '#888',
      'font-size': '11',
    }, f.dayName)
  })

  const highDots = highPoints.map((p, i) =>
    h('g', {},
      h('circle', {
        cx: String(Math.round(p.x)),
        cy: String(Math.round(p.y)),
        r: '4',
        fill: '#ef4444',
      }),
      h('text', {
        x: String(Math.round(p.x)),
        y: String(Math.round(p.y - 10)),
        'text-anchor': 'middle',
        fill: '#ef4444',
        'font-size': '10',
        'font-weight': 'bold',
      }, `${highs[i]}°`)
    )
  )

  const lowDots = lowPoints.map((p, i) =>
    h('g', {},
      h('circle', {
        cx: String(Math.round(p.x)),
        cy: String(Math.round(p.y)),
        r: '4',
        fill: '#3b82f6',
      }),
      h('text', {
        x: String(Math.round(p.x)),
        y: String(Math.round(p.y + 16)),
        'text-anchor': 'middle',
        fill: '#3b82f6',
        'font-size': '10',
        'font-weight': 'bold',
      }, `${lows[i]}°`)
    )
  )

  return h('svg', {
    viewBox: `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`,
    width: '100%',
    height: 'auto',
    style: 'max-width:600px;',
  },
    h('rect', {
      width: String(SVG_WIDTH),
      height: String(SVG_HEIGHT),
      fill: '#fafafa',
      rx: '8',
    }),
    ...gridLines,
    ...dayLabels,
    h('polyline', {
      points: buildPolyline(highPoints),
      fill: 'none',
      stroke: '#ef4444',
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
    }),
    h('polyline', {
      points: buildPolyline(lowPoints),
      fill: 'none',
      stroke: '#3b82f6',
      'stroke-width': '2.5',
      'stroke-linejoin': 'round',
    }),
    ...highDots,
    ...lowDots,
    h('text', {
      x: String(SVG_WIDTH - PADDING.right + 5),
      y: String(Math.round(highPoints[highPoints.length - 1]?.y ?? 0) + 4),
      fill: '#ef4444',
      'font-size': '11',
      'font-weight': 'bold',
    }, 'High'),
    h('text', {
      x: String(SVG_WIDTH - PADDING.right + 5),
      y: String(Math.round(lowPoints[lowPoints.length - 1]?.y ?? 0) + 4),
      fill: '#3b82f6',
      'font-size': '11',
      'font-weight': 'bold',
    }, 'Low'),
  )
}

