import type { DetectedSchema, FieldInfo, FieldType } from './types'

const inferFieldType = (values: unknown[]): FieldType => {
  const nonNull = values.filter((v) => v !== null && v !== undefined && v !== '')
  if (nonNull.length === 0) return 'categorical'

  const numericCount = nonNull.filter((v) => {
    if (typeof v === 'number') return true
    if (typeof v === 'string') {
      const parsed = Number(v)
      return !Number.isNaN(parsed) && v.trim() !== ''
    }
    return false
  }).length

  return numericCount / nonNull.length >= 0.8 ? 'numeric' : 'categorical'
}

export const detectSchema = (data: Record<string, unknown>[]): DetectedSchema => {
  if (!Array.isArray(data) || data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [], rowCount: 0 }
  }

  const keys = new Set<string>()
  for (const row of data) {
    for (const key of Object.keys(row)) {
      keys.add(key)
    }
  }

  const fields: FieldInfo[] = [...keys].map((name) => {
    const values = data.map((row) => row[name])
    const type = inferFieldType(values)
    return {
      name,
      type,
      values: values.map((v) => (type === 'numeric' ? Number(v) || 0 : String(v ?? ''))),
    }
  })

  const numericFields = fields.filter((f) => f.type === 'numeric').map((f) => f.name)
  const categoricalFields = fields.filter((f) => f.type === 'categorical').map((f) => f.name)

  return { fields, numericFields, categoricalFields, rowCount: data.length }
}

export const extractValues = (
  data: Record<string, unknown>[],
  field: string,
): (string | number)[] => data.map((row) => {
  const val = row[field]
  return typeof val === 'number' ? val : String(val ?? '')
})

export const extractNumericValues = (
  data: Record<string, unknown>[],
  field: string,
): number[] => data.map((row) => Number(row[field]) || 0)

import { h } from 'plaited'
import type { FT } from 'plaited'

export type Margin = { top: number; right: number; bottom: number; left: number }

export const DEFAULT_MARGIN: Margin = { top: 40, right: 20, bottom: 60, left: 60 }

export const escapeXml = (str: string): string =>
  str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

export const formatNumber = (n: number): string => {
  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`
  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`
  if (Number.isInteger(n)) return String(n)
  return n.toFixed(1)
}

export const niceScale = (
  min: number,
  max: number,
  ticks = 5,
): { min: number; max: number; step: number; tickValues: number[] } => {
  if (min === max) {
    const padding = min === 0 ? 1 : Math.abs(min) * 0.1
    min -= padding
    max += padding
  }

  const range = max - min
  const roughStep = range / (ticks - 1)
  const magnitude = Math.pow(10, Math.floor(Math.log10(roughStep)))
  const residual = roughStep / magnitude

  let niceStep: number
  if (residual <= 1.5) niceStep = magnitude
  else if (residual <= 3) niceStep = 2 * magnitude
  else if (residual <= 7) niceStep = 5 * magnitude
  else niceStep = 10 * magnitude

  const niceMin = Math.floor(min / niceStep) * niceStep
  const niceMax = Math.ceil(max / niceStep) * niceStep

  const tickValues: number[] = []
  for (let v = niceMin; v <= niceMax + niceStep * 0.01; v += niceStep) {
    tickValues.push(Math.round(v * 1e10) / 1e10)
  }

  return { min: niceMin, max: niceMax, step: niceStep, tickValues }
}

export const renderTitle = (title: string, width: number): FT.Template =>
