import { h } from 'plaited'
import type { FT } from 'plaited'
import type { ChartConfig } from '../types'
import {
  DEFAULT_MARGIN,
  svgWrapper,
  renderTitle,
  renderAxisLabel,
  niceScale,
  formatNumber,
} from './common'

export const renderBarChart = (
  categories: string[],
  values: number[],
  config: ChartConfig,
): FT.Template => {
  const { width, height, title, xLabel, yLabel, colors } = config
  const margin = { ...DEFAULT_MARGIN }
  if (title) margin.top = 50

  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const min = Math.min(0, ...values)
  const max = Math.max(0, ...values)
  const scale = niceScale(min, max)

  const barGroupWidth = plotW / categories.length
  const barPadding = barGroupWidth * 0.2
  const barWidth = barGroupWidth - barPadding * 2

  const yScale = (v: number): number =>
    margin.top + plotH - ((v - scale.min) / (scale.max - scale.min)) * plotH

  const zeroY = yScale(0)

  const bars: FT.Template[] = categories.map((cat, i) => {
    const x = margin.left + i * barGroupWidth + barPadding
    const valY = yScale(values[i])
    const barH = Math.abs(valY - zeroY)
    const barY = values[i] >= 0 ? valY : zeroY
    const color = colors[i % colors.length]

    return h('g', { class: 'bar-group' },
      h('rect', {
        x: String(x),
        y: String(barY),
        width: String(barWidth),
        height: String(Math.max(barH, 1)),
        fill: color,
        rx: '2',
      }),
      h('text', {
        x: String(x + barWidth / 2),
        y: String(margin.top + plotH + 16),
        'text-anchor': 'middle',
        'font-family': 'system-ui, sans-serif',
        'font-size': '11',
        fill: '#666',
      }, cat.length > 10 ? `${cat.slice(0, 9)}...` : cat),
    )
  })

  const gridLines: FT.Template[] = scale.tickValues.map((tick) => {
    const y = yScale(tick)
    return h('g', {},
      h('line', {
        x1: String(margin.left),
        y1: String(y),
        x2: String(margin.left + plotW),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(margin.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-family': 'system-ui, sans-serif',
        'font-size': '11',
        fill: '#666',
      }, formatNumber(tick)),
    )
  })

  const axes: FT.Template[] = [
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top),
      x2: String(margin.left),
      y2: String(margin.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top + plotH),
      x2: String(margin.left + plotW),
      y2: String(margin.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
  ]

  return svgWrapper(width, height, [
    renderTitle(title, width),
    ...gridLines,
    ...axes,
    ...bars,
    renderAxisLabel(xLabel, margin.left + plotW / 2, height - 8),
    renderAxisLabel(yLabel, 16, margin.top + plotH / 2, -90),
  ])
}

import { h } from 'plaited'
import type { FT } from 'plaited'
import type { ChartConfig } from '../types'
import {
  DEFAULT_MARGIN,
  svgWrapper,
  renderTitle,
  renderAxisLabel,
  niceScale,
  formatNumber,
} from './common'

export const renderLineChart = (
  categories: string[],
  valueSets: { label: string; values: number[] }[],
  config: ChartConfig,
): FT.Template => {
  const { width, height, title, xLabel, yLabel, colors } = config
  const margin = { ...DEFAULT_MARGIN }
  if (title) margin.top = 50

  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const allValues = valueSets.flatMap((s) => s.values)
  const min = Math.min(...allValues)
  const max = Math.max(...allValues)
  const scale = niceScale(min, max)

  const xStep = categories.length > 1 ? plotW / (categories.length - 1) : plotW / 2

  const yScale = (v: number): number =>
    margin.top + plotH - ((v - scale.min) / (scale.max - scale.min)) * plotH

  const xScale = (i: number): number =>
    margin.left + (categories.length > 1 ? i * xStep : plotW / 2)

  const lines: FT.Template[] = valueSets.map((series, si) => {
    const color = colors[si % colors.length]
    const points = series.values.map((v, i) => `${xScale(i)},${yScale(v)}`)
    const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'}${p}`).join(' ')

    const dots: FT.Template[] = series.values.map((v, i) =>
      h('circle', {
        cx: String(xScale(i)),
        cy: String(yScale(v)),
        r: '4',
        fill: color,
        stroke: '#fff',
        'stroke-width': '2',
      }),
    )

    return h('g', { class: 'line-series' },
      h('path', {
        d: pathD,
        fill: 'none',
        stroke: color,
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      }),
      ...dots,
    )
  })

  const gridLines: FT.Template[] = scale.tickValues.map((tick) => {
    const y = yScale(tick)
    return h('g', {},
      h('line', {
        x1: String(margin.left),
        y1: String(y),
        x2: String(margin.left + plotW),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(margin.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-family': 'system-ui, sans-serif',
        'font-size': '11',
        fill: '#666',
      }, formatNumber(tick)),
    )
  })

  const xLabels: FT.Template[] = categories.map((cat, i) =>
    h('text', {
      x: String(xScale(i)),
      y: String(margin.top + plotH + 16),
      'text-anchor': 'middle',
      'font-family': 'system-ui, sans-serif',
      'font-size': '11',
      fill: '#666',
    }, cat.length > 10 ? `${cat.slice(0, 9)}...` : cat),
  )

  const axes: FT.Template[] = [
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top),
      x2: String(margin.left),
      y2: String(margin.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top + plotH),
      x2: String(margin.left + plotW),
      y2: String(margin.top + plotH),
      stroke: '#999',
      'stroke-width': '1',
    }),
  ]

  const legend: FT.Template[] = valueSets.length > 1
    ? valueSets.map((series, si) => {
        const lx = margin.left + plotW - 100
        const ly = margin.top + 10 + si * 18
        const color = colors[si % colors.length]
        return h('g', {},
          h('rect', {
            x: String(lx),
            y: String(ly - 8),
            width: '12',
            height: '12',
            fill: color,
            rx: '2',
          }),
          h('text', {
            x: String(lx + 16),
            y: String(ly + 2),
            'font-family': 'system-ui, sans-serif',
            'font-size': '11',
            fill: '#333',
          }, series.label),
        )
      })
    : []

  return svgWrapper(width, height, [
    renderTitle(title, width),
    ...gridLines,
    ...axes,
    ...xLabels,
    ...lines,
    ...legend,
    renderAxisLabel(xLabel, margin.left + plotW / 2, height - 8),
    renderAxisLabel(yLabel, 16, margin.top + plotH / 2, -90),
  ])
}

import { h } from 'plaited'
import type { FT } from 'plaited'
import type { ChartConfig } from '../types'
import { svgWrapper, renderTitle } from './common'

type Slice = {
  label: string
  value: number
  color: string
  startAngle: number
  endAngle: number
}

const describeArc = (
  cx: number,
  cy: number,
  r: number,
  startAngle: number,
  endAngle: number,
): string => {
  const start = {
    x: cx + r * Math.cos(startAngle),
    y: cy + r * Math.sin(startAngle),
  }
  const end = {
    x: cx + r * Math.cos(endAngle),
    y: cy + r * Math.sin(endAngle),
  }
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

export const renderPieChart = (
  categories: string[],
  values: number[],
  config: ChartConfig,
): FT.Template => {
  const { width, height, title, colors } = config
  const titleOffset = title ? 20 : 0

  const cx = width / 2 - 60
  const cy = height / 2 + titleOffset / 2
  const radius = Math.min(cx - 20, cy - 30 - titleOffset)

  const total = values.reduce((sum, v) => sum + Math.abs(v), 0)
  if (total === 0) {
    return svgWrapper(width, height, [
      renderTitle(title, width),
      h('text', {
        x: String(width / 2),
        y: String(height / 2),
        'text-anchor': 'middle',
        'font-family': 'system-ui, sans-serif',
        'font-size': '14',
        fill: '#999',
      }, 'No data to display'),
    ])
  }

  const slices: Slice[] = []
  let angle = -Math.PI / 2

  for (let i = 0; i < categories.length; i++) {
    const fraction = Math.abs(values[i]) / total
    const sliceAngle = fraction * 2 * Math.PI
    slices.push({
      label: categories[i],
      value: values[i],
      color: colors[i % colors.length],
      startAngle: angle,
      endAngle: angle + sliceAngle,
    })
    angle += sliceAngle
  }

  const paths: FT.Template[] = slices.map((slice) => {
    if (slice.endAngle - slice.startAngle >= 2 * Math.PI - 0.001) {
      return h('circle', {
        cx: String(cx),
        cy: String(cy),
        r: String(radius),
        fill: slice.color,
        stroke: '#fff',
        'stroke-width': '2',
      })
    }
    return h('path', {
      d: describeArc(cx, cy, radius, slice.startAngle, slice.endAngle),
      fill: slice.color,
      stroke: '#fff',
      'stroke-width': '2',
    })
  })

  const legendX = cx + radius + 40
  const legendStartY = cy - (slices.length * 22) / 2

  const legendItems: FT.Template[] = slices.map((slice, i) => {
    const ly = legendStartY + i * 22
    const pct = ((Math.abs(slice.value) / total) * 100).toFixed(1)
    return h('g', {},
      h('rect', {
        x: String(legendX),
        y: String(ly - 6),
        width: '12',
        height: '12',
        fill: slice.color,
        rx: '2',
      }),
      h('text', {
        x: String(legendX + 18),
        y: String(ly + 4),
        'font-family': 'system-ui, sans-serif',
        'font-size': '11',
        fill: '#333',
      }, `${slice.label} (${pct}%)`),
    )
  })

  return svgWrapper(width, height, [
    renderTitle(title, width),
    ...paths,
    ...legendItems,
  ])
}

import { createSSR } from 'plaited'
import type { ChartConfig, SVGResult } from './types'
import { detectSchema, extractNumericValues, extractValues } from './detect'
import { renderBarChart } from './svg/bar'
import { renderLineChart } from './svg/line'
import { renderPieChart } from './svg/pie'

export const generateChart = (
  data: Record<string, unknown>[],
  config: ChartConfig,
): SVGResult => {
  try {
    const schema = detectSchema(data)

    if (schema.rowCount === 0) {
      return { svg: '', error: 'No data provided' }
    }

    const categoryField = config.categoryField || schema.categoricalFields[0] || ''
    const valueField = config.valueField || schema.numericFields[0] || ''

    if (!valueField) {
      return { svg: '', error: 'No numeric field found for chart values' }
    }

    const categories = categoryField
      ? extractValues(data, categoryField).map(String)
      : data.map((_, i) => String(i + 1))
    const values = extractNumericValues(data, valueField)

    const resolvedConfig: ChartConfig = { ...config, categoryField, valueField }
    let template

    switch (config.type) {
      case 'bar':
        template = renderBarChart(categories, values, resolvedConfig)
        break

      case 'line': {
        const valueSets = schema.numericFields
          .filter((f) => f === valueField)
          .map((f) => ({
            label: f,
            values: extractNumericValues(data, f),
          }))
        template = renderLineChart(categories, valueSets, resolvedConfig)
        break
      }

      case 'pie':
        template = renderPieChart(categories, values, resolvedConfig)
        break

      default:
        return { svg: '', error: `Unknown chart type: ${config.type}` }
    }

    const ssr = createSSR()
    const svg = ssr.render(template)
    return { svg }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Unknown error'
    return { svg: '', error: message }
  }
}

export const generateMultiLineChart = (
  data: Record<string, unknown>[],
  config: ChartConfig,
  valueFields: string[],
): SVGResult => {
  try {
    const schema = detectSchema(data)

    if (schema.rowCount === 0) {
      return { svg: '', error: 'No data provided' }
    }

    const categoryField = config.categoryField || schema.categoricalFields[0] || ''
    const categories = categoryField
      ? extractValues(data, categoryField).map(String)
      : data.map((_, i) => String(i + 1))

    const valueSets = valueFields.map((f) => ({
      label: f,
      values: extractNumericValues(data, f),
    }))

    const template = renderLineChart(categories, valueSets, config)
    const ssr = createSSR()
    const svg = ssr.render(template)
    return { svg }
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Unknown error'
    return { svg: '', error: message }
  }
}

import { h } from 'plaited'
import type { FT } from 'plaited'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'punctuation'

type Token = {
  type: TokenType
  value: string
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#9876aa',
  string: '#6a8759',
  number: '#6897bb',
  boolean: '#cc7832',
  null: '#cc7832',
  punctuation: '#a9b7c6',
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  const re =
    /("(?:\\.|[^"\\])*")\s*:|("(?:\\.|[^"\\])*")|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([[\]{}:,])|(\s+)/g

  let match: RegExpExecArray | null

  while ((match = re.exec(json)) !== null) {
    if (match[1] !== undefined) {
      tokens.push({ type: 'key', value: match[1] })
      const colonIdx = match[0].indexOf(':', match[1].length)
      if (colonIdx >= 0) {
        tokens.push({ type: 'punctuation', value: ':' })
      }
    } else if (match[2] !== undefined) {
      tokens.push({ type: 'string', value: match[2] })
    } else if (match[3] !== undefined) {
      tokens.push({ type: 'number', value: match[3] })
    } else if (match[4] !== undefined) {
      tokens.push({ type: 'boolean', value: match[4] })
    } else if (match[5] !== undefined) {
      tokens.push({ type: 'null', value: match[5] })
    } else if (match[6] !== undefined) {
      tokens.push({ type: 'punctuation', value: match[6] })
    }
  }

  return tokens
}

export const highlightJson = (json: string): FT.Template => {
  const tokens = tokenize(json)

  const spans: FT.Template[] = []
  let lineNum = 1
  let pos = 0

  const addLineNumber = (): FT.Template =>
    h('span', {
      style: 'color: #606366; user-select: none; display: inline-block; width: 3ch; text-align: right; margin-right: 1ch;',
    }, String(lineNum))

  spans.push(addLineNumber())

  for (const token of tokens) {
    const startIdx = json.indexOf(token.value, pos)
    if (startIdx > pos) {
      const gap = json.slice(pos, startIdx)
      const gapLines = gap.split('\n')
      for (let i = 0; i < gapLines.length; i++) {
        if (i > 0) {
          spans.push(h('br', {}))
          lineNum++
          spans.push(addLineNumber())
        }
        if (gapLines[i]) {
          spans.push(h('span', {}, gapLines[i]))
        }
      }
      pos = startIdx
    }

    spans.push(
      h('span', { style: `color: ${TOKEN_COLORS[token.type]};` }, token.value),
    )
    pos = startIdx + token.value.length
  }

  if (pos < json.length) {
    const remaining = json.slice(pos)
    const lines = remaining.split('\n')
    for (let i = 0; i < lines.length; i++) {
      if (i > 0) {
        spans.push(h('br', {}))
        lineNum++
        spans.push(addLineNumber())
      }
      if (lines[i]) {
        spans.push(h('span', {}, lines[i]))
      }
    }
  }

  return h(
    'pre',
    {
      style:
        'background: #2b2b2b; color: #a9b7c6; padding: 16px; border-radius: 6px; font-family: "JetBrains Mono", "Fira Code", monospace; font-size: 13px; line-height: 1.5; overflow-x: auto; margin: 0; white-space: pre-wrap; word-wrap: break-word;',
    },
    h('code', {}, ...spans),
  )
}

export const validateJson = (input: string): { valid: boolean; error?: string; data?: Record<string, unknown>[] } => {
  try {
    const parsed = JSON.parse(input)
    if (!Array.isArray(parsed)) {
      return { valid: false, error: 'Input must be a JSON array' }
    }
    if (parsed.length === 0) {
      return { valid: false, error: 'Array must not be empty' }
    }
    if (!parsed.every((item: unknown) => typeof item === 'object' && item !== null && !Array.isArray(item))) {
      return { valid: false, error: 'Each array element must be an object' }
    }
    return { valid: true, data: parsed as Record<string, unknown>[] }
  } catch (e) {
    const message = e instanceof SyntaxError ? e.message : 'Invalid JSON'
    return { valid: false, error: message }
  }
}

