import type { ChartConfig, ChartType } from './types'
import { DEFAULT_CONFIG, DEFAULT_COLORS } from './types'
import { detectSchema } from './detect'
import { generateChart, generateMultiLineChart } from './chart'
import { validateJson } from './editor'
import { renderPage } from './render'

const DATA_PATH = './data/current.json'

const loadSavedData = async (): Promise<string> => {
  try {
    const file = Bun.file(DATA_PATH)
    if (await file.exists()) {
      return await file.text()
    }
  } catch {
    // fall through to sample data
  }
  const sample = Bun.file('./data/sample.json')
  return await sample.text()
}

const saveData = async (jsonStr: string): Promise<void> => {
  await Bun.write(DATA_PATH, jsonStr)
}

const parseConfig = (url: URL, schema: ReturnType<typeof detectSchema>): ChartConfig => {
  const type = (url.searchParams.get('type') as ChartType) || DEFAULT_CONFIG.type
  const title = url.searchParams.get('title') || ''
  const xLabel = url.searchParams.get('xLabel') || ''
  const yLabel = url.searchParams.get('yLabel') || ''
  const categoryField = url.searchParams.get('category') || schema.categoricalFields[0] || ''
  const valueField = url.searchParams.get('value') || schema.numericFields[0] || ''

  const colorsParam = url.searchParams.get('colors')
  const colors = colorsParam ? colorsParam.split(',') : DEFAULT_COLORS

  return { type, title, xLabel, yLabel, categoryField, valueField, colors, width: 640, height: 400 }
}

const handleGenerateApi = async (req: Request): Promise<Response> => {
  try {
    const body = await req.json() as {
      data?: unknown
      config?: Partial<ChartConfig>
      valueFields?: string[]
    }

    const { data, config: partialConfig, valueFields } = body

    if (!Array.isArray(data)) {
      return Response.json({ error: 'data must be an array of objects' }, { status: 400 })
    }

    const schema = detectSchema(data as Record<string, unknown>[])
    const config: ChartConfig = { ...DEFAULT_CONFIG, ...partialConfig }

    if (!config.categoryField) config.categoryField = schema.categoricalFields[0] || ''
    if (!config.valueField) config.valueField = schema.numericFields[0] || ''

    let result
    if (config.type === 'line' && valueFields && valueFields.length > 1) {
      result = generateMultiLineChart(data as Record<string, unknown>[], config, valueFields)
    } else {
      result = generateChart(data as Record<string, unknown>[], config)
    }

    if (result.error) {
      return Response.json({ error: result.error }, { status: 400 })
    }

    return new Response(result.svg, {
      headers: { 'Content-Type': 'image/svg+xml' },
    })
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Internal error'
    return Response.json({ error: message }, { status: 500 })
  }
}

const handleDownload = async (req: Request): Promise<Response> => {
  try {
    const body = await req.json() as {
      data?: unknown
      config?: Partial<ChartConfig>
    }

    const data = body.data as Record<string, unknown>[]
    const schema = detectSchema(data)
    const config: ChartConfig = { ...DEFAULT_CONFIG, ...body.config }
    if (!config.categoryField) config.categoryField = schema.categoricalFields[0] || ''
    if (!config.valueField) config.valueField = schema.numericFields[0] || ''

    const result = generateChart(data, config)

    if (result.error) {
      return Response.json({ error: result.error }, { status: 400 })
    }

    const filename = `chart-${config.type}-${Date.now()}.svg`

    return new Response(result.svg, {
      headers: {
        'Content-Type': 'image/svg+xml',
        'Content-Disposition': `attachment; filename="${filename}"`,
      },
    })
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Internal error'
    return Response.json({ error: message }, { status: 500 })
  }
}

const handleSchema = async (req: Request): Promise<Response> => {
  try {
    const body = await req.json() as { data?: unknown }
    const data = body.data as Record<string, unknown>[]
    const schema = detectSchema(data)
    return Response.json(schema)
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Internal error'
    return Response.json({ error: message }, { status: 500 })
  }
}

const handleSave = async (req: Request): Promise<Response> => {
  try {
    const body = await req.json() as { data?: string }
    if (typeof body.data !== 'string') {
      return Response.json({ error: 'data must be a JSON string' }, { status: 400 })
    }
    const validation = validateJson(body.data)
    if (!validation.valid) {
      return Response.json({ error: validation.error }, { status: 400 })
    }
    await saveData(body.data)
    return Response.json({ ok: true })
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Internal error'
    return Response.json({ error: message }, { status: 500 })
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'POST' && url.pathname === '/api/generate') {
      return handleGenerateApi(req)
    }
    if (req.method === 'POST' && url.pathname === '/api/download') {
      return handleDownload(req)
    }
    if (req.method === 'POST' && url.pathname === '/api/schema') {
      return handleSchema(req)
    }
    if (req.method === 'POST' && url.pathname === '/api/save') {
      return handleSave(req)
    }

    // Serve main UI
    const jsonStr = await loadSavedData()
    const validation = validateJson(jsonStr)
    const data = validation.data ?? []
    const schema = detectSchema(data)
    const config = parseConfig(url, schema)

    const generateOnLoad = url.searchParams.has('generate')
    let svgContent = ''
    let chartError: string | undefined

    if (generateOnLoad) {
      const result = generateChart(data, config)
      svgContent = result.svg
      chartError = result.error
    }

    const html = renderPage(
      jsonStr,
      schema,
      config,
      svgContent,
      chartError,
      validation.valid ? undefined : validation.error,
    )

    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

