import { loadMarkers, loadCircles, addMarker, removeMarker, addCircle, removeCircle, searchLocation } from "./store";
import { renderToHtml } from "./render";
import { CATEGORIES } from "./categories";
import type { MarkerCategory } from "./types";

export const createMapApp = async (): Promise<string> => {
  const markers = await loadMarkers();
  const circles = await loadCircles();
  const activeCategories: MarkerCategory[] = CATEGORIES.map((c) => c.name);
  return renderToHtml(markers, circles, activeCategories);
};

export const serve = () => {
  const server = Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url);

      if (url.pathname === "/" || url.pathname === "/index.html") {
        const html = await createMapApp();
        return new Response(html, {
          headers: { "Content-Type": "text/html; charset=utf-8" },
        });
      }

      if (url.pathname === "/api/markers" && req.method === "GET") {
        const markers = await loadMarkers();
        return Response.json(markers);
      }

      if (url.pathname === "/api/markers" && req.method === "POST") {
        const body = await req.json();
        const marker = await addMarker(body);
        return Response.json(marker, { status: 201 });
      }

      if (url.pathname.startsWith("/api/markers/") && req.method === "DELETE") {
        const id = url.pathname.split("/").pop()!;
        await removeMarker(id);
        return new Response(null, { status: 204 });
      }

      if (url.pathname === "/api/circles" && req.method === "GET") {
        const circles = await loadCircles();
        return Response.json(circles);
      }

      if (url.pathname === "/api/circles" && req.method === "POST") {
        const body = await req.json();
        const circle = await addCircle(body);
        return Response.json(circle, { status: 201 });
      }

      if (url.pathname.startsWith("/api/circles/") && req.method === "DELETE") {
        const id = url.pathname.split("/").pop()!;
        await removeCircle(id);
        return new Response(null, { status: 204 });
      }

      if (url.pathname === "/api/search" && req.method === "GET") {
        const query = url.searchParams.get("q");
        if (!query) return Response.json({ error: "Missing q parameter" }, { status: 400 });
        const result = await searchLocation(query);
        if (!result) return Response.json({ error: "Not found" }, { status: 404 });
        return Response.json(result);
      }

      return new Response("Not Found", { status: 404 });
    },
  });

  console.log(`Interactive Map running at http://localhost:${server.port}`);
  return server;
};

