type Category = 'length' | 'weight' | 'temperature' | 'volume' | 'time'

type UnitDef = {
  symbol: string
  name: string
  toBase: number
}

type TemperatureUnit = 'C' | 'F' | 'K'

type CategoryConfig = {
  label: string
  baseUnit: string
  units: UnitDef[]
}

type ConversionResult = {
  from: string
  to: string
  inputValue: number
  outputValue: number
  formula: string
}

const categories: Record<Category, CategoryConfig> = {
  length: {
    label: 'Length',
