    units: [
      { symbol: 'mg', name: 'Milligram', toBase: 0.001 },
      { symbol: 'g', name: 'Gram', toBase: 1 },
      { symbol: 'kg', name: 'Kilogram', toBase: 1000 },
      { symbol: 'lb', name: 'Pound', toBase: 453.592 },
      { symbol: 'oz', name: 'Ounce', toBase: 28.3495 },
    ],
  },
  temperature: {
    label: 'Temperature',
    baseUnit: 'C',
    units: [
      { symbol: 'C', name: 'Celsius', toBase: 1 },
      { symbol: 'F', name: 'Fahrenheit', toBase: 1 },
      { symbol: 'K', name: 'Kelvin', toBase: 1 },
    ],
  },
  volume: {
    label: 'Volume',
    baseUnit: 'ml',
    units: [
      { symbol: 'ml', name: 'Milliliter', toBase: 1 },
      { symbol: 'l', name: 'Liter', toBase: 1000 },
      { symbol: 'gal', name: 'Gallon', toBase: 3785.41 },
      { symbol: 'qt', name: 'Quart', toBase: 946.353 },
      { symbol: 'pt', name: 'Pint', toBase: 473.176 },
      { symbol: 'cup', name: 'Cup', toBase: 236.588 },
      { symbol: 'tbsp', name: 'Tablespoon', toBase: 14.7868 },
      { symbol: 'tsp', name: 'Teaspoon', toBase: 4.92892 },
    ],
  },
  time: {
    label: 'Time',
    baseUnit: 's',
    units: [
      { symbol: 'ms', name: 'Millisecond', toBase: 0.001 },
      { symbol: 's', name: 'Second', toBase: 1 },
      { symbol: 'min', name: 'Minute', toBase: 60 },
      { symbol: 'hr', name: 'Hour', toBase: 3600 },
      { symbol: 'day', name: 'Day', toBase: 86400 },
      { symbol: 'week', name: 'Week', toBase: 604800 },
    ],
  },
}

const convertTemperature = (value: number, from: TemperatureUnit, to: TemperatureUnit): number => {
  if (from === to) return value

  let celsius: number
  if (from === 'C') celsius = value
  else if (from === 'F') celsius = (value - 32) * 5 / 9
  else celsius = value - 273.15

  if (to === 'C') return celsius
  if (to === 'F') return celsius * 9 / 5 + 32
  return celsius + 273.15
}

const getTemperatureFormula = (from: TemperatureUnit, to: TemperatureUnit): string => {
  const formulas: Record<string, string> = {
    'C→F': '°F = °C × 9/5 + 32',
    'F→C': '°C = (°F − 32) × 5/9',
    'C→K': 'K = °C + 273.15',
    'K→C': '°C = K − 273.15',
    'F→K': 'K = (°F − 32) × 5/9 + 273.15',
    'K→F': '°F = (K − 273.15) × 9/5 + 32',
  }
  if (from === to) return `${from} = ${to} (no conversion)`
  return formulas[`${from}→${to}`] ?? ''
}

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  const fixed = n.toPrecision(8)
  return parseFloat(fixed).toString()
}

const convert = (category: Category, value: number, fromSymbol: string, toSymbol: string): ConversionResult => {
  const config = categories[category]

  if (category === 'temperature') {
    const from = fromSymbol as TemperatureUnit
    const to = toSymbol as TemperatureUnit
    const result = convertTemperature(value, from, to)
    return {
      from: fromSymbol,
      to: toSymbol,
      inputValue: value,
      outputValue: result,
      formula: getTemperatureFormula(from, to),
    }
  }

  const fromUnit = config.units.find(u => u.symbol === fromSymbol)
  const toUnit = config.units.find(u => u.symbol === toSymbol)

  if (!fromUnit || !toUnit) {
    return { from: fromSymbol, to: toSymbol, inputValue: value, outputValue: 0, formula: 'Unknown unit' }
  }

  const factor = fromUnit.toBase / toUnit.toBase
  const result = value * factor

  const formula = fromSymbol === toSymbol
    ? `${fromSymbol} = ${toSymbol} (no conversion)`
    : `1 ${fromSymbol} = ${formatNumber(factor)} ${toSymbol}`

  return {
    from: fromSymbol,
    to: toSymbol,
    inputValue: value,
    outputValue: result,
    formula,
  }
}

const getCategories = (): Record<Category, CategoryConfig> => categories

const getCategoryList = (): Category[] => ['length', 'weight', 'temperature', 'volume', 'time']

