type ConverterState = {
  activeCategory: Category
  inputValue: number
  fromUnit: string
  toUnit: string
}

const getDefaultState = (category: Category): ConverterState => {
  const config = getCategories()[category]
  return {
    activeCategory: category,
    inputValue: 1,
    fromUnit: config.units[0].symbol,
    toUnit: config.units.length > 1 ? config.units[1].symbol : config.units[0].symbol,
  }
}

const handleConvert = (state: ConverterState): ConversionResult => {
  return convert(state.activeCategory, state.inputValue, state.fromUnit, state.toUnit)
}

const handleCategoryChange = (state: ConverterState, category: Category): ConverterState => {
  const defaults = getDefaultState(category)
  return { ...defaults, inputValue: state.inputValue }
}

const handleSwapUnits = (state: ConverterState): ConverterState => ({
  ...state,
  fromUnit: state.toUnit,
  toUnit: state.fromUnit,
})

const handleValueChange = (state: ConverterState, value: number): ConverterState => ({
  ...state,
  inputValue: isNaN(value) ? 0 : value,
})

const handleUnitChange = (
  state: ConverterState,
  which: 'fromUnit' | 'toUnit',
  unit: string,
): ConverterState => ({
  ...state,
  [which]: unit,
})

const render = (state?: ConverterState): string => {
  const s = state ?? getDefaultState('length')
  const template = renderConverter(s.activeCategory, s.inputValue, s.fromUnit, s.toUnit)
  const ssr = createSSR()
  return ssr(template)
}

const quickConvert = (
  category: Category,
  value: number,
  from: string,
  to: string,
): string => {
  const result = convert(category, value, from, to)
  return `${formatNumber(result.inputValue)} ${result.from} = ${formatNumber(result.outputValue)} ${result.to} | Formula: ${result.formula}`
}

export {
  render,
  quickConvert,
  handleConvert,
  handleCategoryChange,
  handleSwapUnits,
  handleValueChange,
  handleUnitChange,
  getDefaultState,
  getCategories,
  getCategoryList,
}
export type { ConverterState }

