export type EventCategory = 'work' | 'personal' | 'health' | 'social';

export type Recurrence = 'daily' | 'weekly' | 'monthly' | 'none';

export type CalendarEvent = {
  id: string;
  title: string;
  date: string;       // ISO date: YYYY-MM-DD
  startTime: string;  // HH:MM (24h)
  endTime: string;    // HH:MM (24h)
  description: string;
  category: EventCategory;
  recurrence: Recurrence;
};

export type DayCell = {
  date: string;        // YYYY-MM-DD
  dayNumber: number;
  isCurrentMonth: boolean;
  isToday: boolean;
  events: CalendarEvent[];
};

export type MonthGrid = {
  year: number;
  month: number;       // 1-12
  label: string;       // e.g. "March 2026"
  weeks: DayCell[][];  // 6 rows × 7 cols
};

export type CalendarView = 'month' | 'day';

export type CalendarState = {
  view: CalendarView;
  year: number;
  month: number;
  selectedDate: string | null;
};

export const CATEGORY_COLORS: Record<EventCategory, string> = {
  work: '#3b82f6',
  personal: '#22c55e',
  health: '#f97316',
  social: '#a855f7',
};

import { type CalendarEvent } from './types';

const DATA_PATH = new URL('./data/events.jsonl', import.meta.url).pathname;

const generateId = (): string =>
  crypto.randomUUID();

const readAll = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as CalendarEvent);
};

const writeAll = async (events: CalendarEvent[]): Promise<void> => {
  const content = events.map((e) => JSON.stringify(e)).join('\n') + (events.length ? '\n' : '');
  await Bun.write(DATA_PATH, content);
};

export const createEvent = async (
  input: Omit<CalendarEvent, 'id'>
): Promise<CalendarEvent> => {
  const events = await readAll();
  const event: CalendarEvent = { id: generateId(), ...input };
  events.push(event);
  await writeAll(events);
  return event;
};

export const getEvents = async (): Promise<CalendarEvent[]> =>
  readAll();

export const getEventById = async (id: string): Promise<CalendarEvent | undefined> => {
  const events = await readAll();
  return events.find((e) => e.id === id);
};

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | undefined> => {
  const events = await readAll();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) return undefined;
  events[idx] = { ...events[idx], ...updates };
  await writeAll(events);
  return events[idx];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await readAll();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await writeAll(filtered);
  return true;
};

import { type CalendarEvent, type DayCell, type MonthGrid, type Recurrence } from './types';

const WEEKDAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTHS = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const formatDate = (d: Date): string =>
  `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;

const todayStr = (): string => formatDate(new Date());

const addDays = (d: Date, n: number): Date => {
  const r = new Date(d);
  r.setDate(r.getDate() + n);
  return r;
};

const addMonths = (d: Date, n: number): Date => {
  const r = new Date(d);
  r.setMonth(r.getMonth() + n);
  return r;
};

const occursOn = (event: CalendarEvent, targetDate: string): boolean => {
  const eventDate = new Date(event.date + 'T00:00:00');
  const target = new Date(targetDate + 'T00:00:00');

  if (target < eventDate) return false;
  if (event.date === targetDate) return true;
  if (event.recurrence === 'none') return false;

  const diffTime = target.getTime() - eventDate.getTime();
  const diffDays = Math.round(diffTime / (1000 * 60 * 60 * 24));

  switch (event.recurrence) {
    case 'daily':
      return diffDays >= 0;
    case 'weekly':
      return diffDays % 7 === 0;
    case 'monthly':
      return target.getDate() === eventDate.getDate() && target >= eventDate;
    default:
      return false;
  }
};

export const getEventsForDate = (events: CalendarEvent[], date: string): CalendarEvent[] =>
  events
    .filter((e) => occursOn(e, date))
    .sort((a, b) => a.startTime.localeCompare(b.startTime));

export const buildMonthGrid = (year: number, month: number, events: CalendarEvent[]): MonthGrid => {
  const firstDay = new Date(year, month - 1, 1);
  const startOffset = firstDay.getDay(); // 0=Sun
  const gridStart = addDays(firstDay, -startOffset);
  const today = todayStr();

  const weeks: DayCell[][] = [];

  for (let w = 0; w < 6; w++) {
    const week: DayCell[] = [];
    for (let d = 0; d < 7; d++) {
      const current = addDays(gridStart, w * 7 + d);
      const dateStr = formatDate(current);
      week.push({
        date: dateStr,
        dayNumber: current.getDate(),
        isCurrentMonth: current.getMonth() === month - 1,
        isToday: dateStr === today,
        events: getEventsForDate(events, dateStr),
      });
    }
    weeks.push(week);
  }

  return {
    year,
    month,
    label: `${MONTHS[month - 1]} ${year}`,
    weeks,
  };
};

export const getWeekdayHeaders = (): string[] => WEEKDAYS;

