const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${typeof v === 'number' ? `${v}px` : v}`)
    .join(';');

const renderCategoryBadge = (category: EventCategory) =>
  h('span', { style: styleToStr({ ...styles.badge, background: CATEGORY_COLORS[category] }) }, category);

const renderEventDots = (events: CalendarEvent[]) => {
  const seen = new Set<EventCategory>();
  const dots: ReturnType<typeof h>[] = [];
  for (const e of events) {
    if (!seen.has(e.category)) {
      seen.add(e.category);
      dots.push(
        h('span', {
          style: styleToStr({ ...styles.eventDot, background: CATEGORY_COLORS[e.category] }),
        })
      );
    }
  }
  return h('div', {}, ...dots);
};

const renderEventPills = (events: CalendarEvent[]) => {
  const visible = events.slice(0, 2);
  const remaining = events.length - visible.length;
  const pills = visible.map((e) =>
    h(
      'span',
      { style: styleToStr({ ...styles.eventPill, background: CATEGORY_COLORS[e.category] }) },
      e.title
    )
  );
  if (remaining > 0) {
    pills.push(
      h('span', { style: 'font-size:10px;color:#64748b' }, `+${remaining} more`)
    );
  }
  return h(Fragment, {}, ...pills);
};

