const createInitialState = (): CalendarState => {
  const now = new Date();
  return {
    view: 'month',
    year: now.getFullYear(),
    month: now.getMonth() + 1,
    selectedDate: null,
  };
};

let state = createInitialState();

export const getState = (): CalendarState => ({ ...state });

export const navigateMonth = (direction: 'prev' | 'next'): void => {
  if (direction === 'next') {
    if (state.month === 12) {
      state = { ...state, month: 1, year: state.year + 1 };
    } else {
      state = { ...state, month: state.month + 1 };
    }
  } else {
    if (state.month === 1) {
      state = { ...state, month: 12, year: state.year - 1 };
    } else {
      state = { ...state, month: state.month - 1 };
    }
  }
};

export const selectDate = (date: string): void => {
  state = { ...state, view: 'day', selectedDate: date };
};

export const backToMonth = (): void => {
  state = { ...state, view: 'month', selectedDate: null };
};

export const renderCurrentView = async (): Promise<string> => {
  const events = await getEvents();

  if (state.view === 'month') {
    const grid = buildMonthGrid(state.year, state.month, events);
    const template = renderMonthView(grid);
    return String(template);
  }

  if (state.view === 'day' && state.selectedDate) {
    const dayEvents = getEventsForDate(events, state.selectedDate);
    const template = renderDayView(state.selectedDate, dayEvents);
    return String(template);
  }

  return '';
};

export const renderAddForm = (date?: string): string => {
  const targetDate = date ?? state.selectedDate ?? todayStr();
  const template = renderEventForm(targetDate);
  return String(template);
};

export const renderEditForm = async (eventId: string): Promise<string> => {
  const event = await getEventById(eventId);
  if (!event) return '<div>Event not found</div>';
  const template = renderEventForm(event.date, event);
  return String(template);
};

export const handleCreateEvent = async (input: {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description: string;
  category: EventCategory;
  recurrence: Recurrence;
}): Promise<CalendarEvent> =>
  createEvent(input);

export const handleUpdateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | undefined> =>
  updateEvent(id, updates);

export const handleDeleteEvent = async (id: string): Promise<boolean> =>
  deleteEvent(id);

export const getEventsForSelectedDate = async (): Promise<CalendarEvent[]> => {
  if (!state.selectedDate) return [];
  const events = await getEvents();
  return getEventsForDate(events, state.selectedDate);
};

