const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const renderInline = (text: string): string => {
  let result = text
  // Images (must come before links)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const renderTable = (lines: string[]): string => {
  const rows = lines.map((line) =>
    line
      .split('|')
      .map((cell) => cell.trim())
      .filter((cell) => cell.length > 0)
  )
  if (rows.length < 2) return lines.map((l) => `<p>${renderInline(escapeHtml(l))}</p>`).join('\n')

  const header = rows[0]
  const bodyRows = rows.slice(2) // skip separator row

  const headerHtml = header.map((cell) => `<th>${renderInline(escapeHtml(cell))}</th>`).join('')
  const bodyHtml = bodyRows
    .map((row) => {
      const cells = row.map((cell) => `<td>${renderInline(escapeHtml(cell))}</td>`).join('')
      return `<tr>${cells}</tr>`
    })
    .join('\n')

  return `<table>\n<thead><tr>${headerHtml}</tr></thead>\n<tbody>\n${bodyHtml}\n</tbody>\n</table>`
}

const isTableSeparator = (line: string): boolean => /^\|?[\s\-:|]+\|[\s\-:|]+\|?$/.test(line)

export const renderMarkdown = (markdown: string): string => {
  const lines = markdown.split('\n')
  const output: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code block
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      output.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // Table
    if (line.includes('|') && i + 1 < lines.length && isTableSeparator(lines[i + 1])) {
      const tableLines: string[] = [line]
      i++
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      output.push(renderTable(tableLines))
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
      output.push('<hr />')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${renderInline(escapeHtml(headingMatch[2]))}</h${level}>`)
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('> ') || line === '>') {
      const quoteLines: string[] = []
      while (i < lines.length && (lines[i].startsWith('> ') || lines[i] === '>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${renderInline(escapeHtml(quoteLines.join('\n')))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\-\*\+]\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^[\-\*\+]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^[\-\*\+]\s+/, ''))
        i++
      }
      const listHtml = items
        .map((item) => `<li>${renderInline(escapeHtml(item))}</li>`)
        .join('\n')
      output.push(`<ul>\n${listHtml}\n</ul>`)
      continue
    }

    // Ordered list
    if (/^\d+\.\s+/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\d+\.\s+/, ''))
        i++
      }
      const listHtml = items
        .map((item) => `<li>${renderInline(escapeHtml(item))}</li>`)
        .join('\n')
      output.push(`<ol>\n${listHtml}\n</ol>`)
      continue
    }

    // Empty line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !lines[i].startsWith('#') && !lines[i].startsWith('```') && !lines[i].startsWith('> ') && !/^[\-\*\+]\s+/.test(lines[i]) && !/^\d+\.\s+/.test(lines[i]) && !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i])) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${renderInline(escapeHtml(paraLines.join('\n')))}</p>`)
    }
  }

  return output.join('\n')
}

import type { Document, DocumentList, SaveDocumentRequest } from './types'

const DATA_PATH = `${import.meta.dir}/data/documents.json`

const readDocuments = async (): Promise<DocumentList> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as DocumentList
}

const writeDocuments = async (docs: DocumentList): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const listDocuments = async (): Promise<DocumentList> => {
  const docs = await readDocuments()
  return docs.map(({ id, title, createdAt, updatedAt }) => ({
    id,
    title,
    content: '',
    createdAt,
    updatedAt,
  }))
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id) ?? null
}

export const saveDocument = async (req: SaveDocumentRequest): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()

  if (req.id) {
    const idx = docs.findIndex((d) => d.id === req.id)
    if (idx !== -1) {
      docs[idx] = {
        ...docs[idx],
        title: req.title,
        content: req.content,
        updatedAt: now,
      }
      await writeDocuments(docs)
      return docs[idx]
    }
  }

  const doc: Document = {
    id: crypto.randomUUID(),
    title: req.title,
    content: req.content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const filtered = docs.filter((d) => d.id !== id)
  if (filtered.length === docs.length) return false
  await writeDocuments(filtered)
  return true
}

