import { h, Fragment } from 'plaited'
import { createSSR } from 'plaited/server'
import { styles, previewStyles, styleToString } from './styles'
import { toolbarItems } from './toolbar'
import { renderMarkdown } from './markdown'
import type { DocumentList } from './types'

const toolbarButtonsHtml = toolbarItems
  .map(
    (item) =>
      `<button style="${styleToString(styles.toolbarBtn as unknown as Record<string, string>)}" p-trigger="click->toolbar" data-action="${item.action}" title="${item.action}">${item.label}</button>`
  )
