export const renderEditorPage = (params: {
  documents: DocumentList
  currentTitle: string
  currentContent: string
  currentId: string
  showSidebar: boolean
}): string => {
  const { documents, currentTitle, currentContent, currentId, showSidebar } = params
  const previewHtml = renderMarkdown(currentContent)

  const docListItems = documents
    .map(
      (doc) =>
        `<div style="${styleToString(styles.docItem as unknown as Record<string, string>)}" class="doc-item">
          <span style="${styleToString(styles.docItemTitle as unknown as Record<string, string>)}" data-id="${doc.id}" p-trigger="click->loadDoc">${escapeAttr(doc.title)}</span>
          <button style="${styleToString(styles.deleteBtn as unknown as Record<string, string>)}" data-id="${doc.id}" p-trigger="click->deleteDoc">x</button>
        </div>`
    )
    .join('\n')

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Markdown Editor</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { ${styleToString(styles.root as unknown as Record<string, string>)} }
    ${previewStyles}
    .toolbar-btn:hover { background-color: #45475a !important; }
    .doc-item:hover { background-color: #313244; }
  </style>
</head>
<body>
  <div style="${styleToString(styles.header as unknown as Record<string, string>)}">
    <span style="${styleToString(styles.title as unknown as Record<string, string>)}">Markdown Editor</span>
    <div style="${styleToString(styles.headerActions as unknown as Record<string, string>)}">
      <input id="doc-title" type="text" placeholder="Document title..." value="${escapeAttr(currentTitle)}" style="${styleToString(styles.input as unknown as Record<string, string>)}" />
      <input id="doc-id" type="hidden" value="${escapeAttr(currentId)}" />
      <button id="save-btn" style="${styleToString(styles.saveBtn as unknown as Record<string, string>)}">Save</button>
      <button id="new-btn" style="${styleToString(styles.docListBtn as unknown as Record<string, string>)}">New</button>
      <button id="sidebar-toggle" style="${styleToString(styles.docListBtn as unknown as Record<string, string>)}">Documents</button>
    </div>
  </div>

  <div style="${styleToString(styles.toolbar as unknown as Record<string, string>)}">
    ${toolbarButtonsHtml}
  </div>

  <div style="${styleToString(styles.splitPane as unknown as Record<string, string>)}">
    ${showSidebar ? `<div id="sidebar" style="${styleToString(styles.sidebar as unknown as Record<string, string>)}">
      <div style="${styleToString(styles.sidebarTitle as unknown as Record<string, string>)}">Saved Documents</div>
      <div style="${styleToString(styles.sidebarList as unknown as Record<string, string>)}">
        ${docListItems || '<div style="padding: 12px; color: #6c7086; font-size: 13px;">No saved documents</div>'}
      </div>
    </div>` : ''}

    <div style="${styleToString(styles.editorPane as unknown as Record<string, string>)}">
      <div style="${styleToString(styles.paneLabel as unknown as Record<string, string>)}">Editor</div>
      <textarea id="editor" style="${styleToString(styles.textarea as unknown as Record<string, string>)}" placeholder="Write your markdown here...">${escapeAttr(currentContent)}</textarea>
    </div>

    <div style="${styleToString(styles.previewPane as unknown as Record<string, string>)}">
      <div style="${styleToString(styles.paneLabel as unknown as Record<string, string>)}">Preview</div>
      <div id="preview" class="preview" style="${styleToString(styles.previewContent as unknown as Record<string, string>)}">${previewHtml}</div>
    </div>
  </div>

  <script>
    const editor = document.getElementById('editor');
    const preview = document.getElementById('preview');
    const titleInput = document.getElementById('doc-title');
    const docIdInput = document.getElementById('doc-id');
    const saveBtn = document.getElementById('save-btn');
    const newBtn = document.getElementById('new-btn');
    const sidebarToggle = document.getElementById('sidebar-toggle');

    // Live preview with debounce
    let debounceTimer;
    editor.addEventListener('input', () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const res = await fetch('/render', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ markdown: editor.value }),
        });
        const data = await res.json();
        preview.innerHTML = data.html;
      }, 150);
    });

    // Toolbar actions
    const toolbarConfig = ${JSON.stringify(toolbarItems)};
    document.querySelectorAll('[data-action]').forEach((btn) => {
      btn.addEventListener('click', () => {
        const action = btn.getAttribute('data-action');
        const item = toolbarConfig.find((t) => t.action === action);
        if (!item) return;

        const start = editor.selectionStart;
        const end = editor.selectionEnd;
        const selected = editor.value.substring(start, end);
        const content = selected || item.placeholder;
        const insert = item.suffix ? item.prefix + content + item.suffix : item.prefix + content;

        editor.value = editor.value.substring(0, start) + insert + editor.value.substring(end);
        editor.focus();

        if (!selected) {
          const cursorPos = start + item.prefix.length;
          editor.setSelectionRange(cursorPos, cursorPos + (content.length));
        } else {
          editor.setSelectionRange(start, start + insert.length);
        }

        editor.dispatchEvent(new Event('input'));
      });
    });

    // Save document
    saveBtn.addEventListener('click', async () => {
      const title = titleInput.value.trim() || 'Untitled';
      const res = await fetch('/documents', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title,
          content: editor.value,
          id: docIdInput.value || undefined,
        }),
      });
      const doc = await res.json();
      docIdInput.value = doc.id;
      titleInput.value = doc.title;
      window.location.reload();
    });

    // New document
    newBtn.addEventListener('click', () => {
      editor.value = '';
      titleInput.value = '';
      docIdInput.value = '';
      preview.innerHTML = '';
    });

    // Sidebar toggle
    sidebarToggle.addEventListener('click', () => {
      const showingSidebar = window.location.search.includes('sidebar=true');
      window.location.search = showingSidebar ? '' : 'sidebar=true';
    });

    // Load document
    document.querySelectorAll('[p-trigger="click->loadDoc"]').forEach((el) => {
      el.addEventListener('click', async () => {
        const id = el.getAttribute('data-id');
        const res = await fetch('/documents/' + id);
        const doc = await res.json();
        editor.value = doc.content;
        titleInput.value = doc.title;
        docIdInput.value = doc.id;
        editor.dispatchEvent(new Event('input'));
      });
    });

    // Delete document
    document.querySelectorAll('[p-trigger="click->deleteDoc"]').forEach((el) => {
      el.addEventListener('click', async (e) => {
        e.stopPropagation();
        const id = el.getAttribute('data-id');
        if (!confirm('Delete this document?')) return;
        await fetch('/documents/' + id, { method: 'DELETE' });
        window.location.reload();
      });
    });

    // Tab key inserts spaces
    editor.addEventListener('keydown', (e) => {
      if (e.key === 'Tab') {
        e.preventDefault();
        const start = editor.selectionStart;
        editor.value = editor.value.substring(0, start) + '  ' + editor.value.substring(editor.selectionEnd);
        editor.selectionStart = editor.selectionEnd = start + 2;
      }
    });
  </script>
</body>
</html>`
}

const escapeAttr = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')

