const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    // Render markdown to HTML
    if (pathname === '/render' && req.method === 'POST') {
      const body = (await req.json()) as RenderRequest
      const html = renderMarkdown(body.markdown)
      return Response.json({ html })
    }

    // List documents
    if (pathname === '/documents' && req.method === 'GET') {
      const docs = await listDocuments()
      return Response.json(docs)
    }

    // Save document
    if (pathname === '/documents' && req.method === 'POST') {
      const body = (await req.json()) as SaveDocumentRequest
      const doc = await saveDocument(body)
      return Response.json(doc)
    }

    // Get document
    const docMatch = pathname.match(/^\/documents\/(.+)$/)
    if (docMatch && req.method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(doc)
    }

    // Delete document
    if (docMatch && req.method === 'DELETE') {
      const deleted = await deleteDocument(docMatch[1])
      if (!deleted) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json({ ok: true })
    }

    // Main editor page
    if (pathname === '/') {
      const showSidebar = url.searchParams.get('sidebar') === 'true'
      const documents = await listDocuments()
      const html = renderEditorPage({
        documents,
        currentTitle: '',
        currentContent: DEFAULT_MARKDOWN,
        currentId: '',
        showSidebar,
      })
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return Response.json({ error: 'Not found' }, { status: 404 })
  },
})

