/** Core color types and conversion utilities */

export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }
export type Color = {
  hex: string
  rgb: RGB
  hsl: HSL
}

/** Parse a hex string (with or without #) into RGB */
export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const expanded =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const num = parseInt(expanded, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

/** Convert RGB to hex string */
export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.max(0, Math.min(255, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

/** Convert RGB to HSL (h: 0-360, s: 0-100, l: 0-100) */
export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) {
    return { h: 0, s: 0, l: Math.round(l * 100) }
  }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h: number
  if (max === r) {
    h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  } else if (max === g) {
    h = ((b - r) / d + 2) / 6
  } else {
    h = ((r - g) / d + 4) / 6
  }
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

/** Convert HSL to RGB */
export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

/** Build a full Color object from a hex string */
export const colorFromHex = (hex: string): Color => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

/** Build a full Color object from an HSL value */
export const colorFromHsl = (hsl: HSL): Color => {
  const rgb = hslToRgb(hsl)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

/** Normalize hue to 0-359 range */
export const normalizeHue = (h: number): number => ((h % 360) + 360) % 360

/** Validate a hex color string */
export const isValidHex = (hex: string): boolean =>
  /^#?([0-9A-Fa-f]{3}|[0-9A-Fa-f]{6})$/.test(hex)

/** Format RGB as a CSS string */
export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

/** Format HSL as a CSS string */
export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

/** Color harmony generation using color theory */

import { type Color, type HSL, colorFromHex, colorFromHsl, normalizeHue } from './color'

export type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  mode: HarmonyMode
  base: Color
  colors: Color[]
}

/** Derive colors at given hue offsets from a base HSL */
const deriveColors = (base: HSL, offsets: number[]): Color[] =>
  offsets.map((offset) =>
    colorFromHsl({
      h: normalizeHue(base.h + offset),
      s: base.s,
      l: base.l,
    }),
  )

/** Generate a complementary palette (base + 180°) */
const complementary = (base: Color): Color[] => deriveColors(base.hsl, [0, 180])

/** Generate an analogous palette (base ± 30°) */
const analogous = (base: Color): Color[] => deriveColors(base.hsl, [-30, 0, 30])

/** Generate a triadic palette (base + 120° + 240°) */
const triadic = (base: Color): Color[] => deriveColors(base.hsl, [0, 120, 240])

/** Generate a split-complementary palette (base + 150° + 210°) */
const splitComplementary = (base: Color): Color[] => deriveColors(base.hsl, [0, 150, 210])

/** Generate a tetradic palette (base + 90° + 180° + 270°) */
const tetradic = (base: Color): Color[] => deriveColors(base.hsl, [0, 90, 180, 270])

const generators: Record<HarmonyMode, (base: Color) => Color[]> = {
  complementary,
  analogous,
  triadic,
  'split-complementary': splitComplementary,
  tetradic,
}

/** Generate a harmonious color palette from a base hex color */
export const generatePalette = (baseHex: string, mode: HarmonyMode): Palette => {
  const base = colorFromHex(baseHex)
  const colors = generators[mode](base)
  return { mode, base, colors }
}

/** Generate all harmony palettes for a given base color */
export const generateAllPalettes = (baseHex: string): Palette[] => {
  const modes: HarmonyMode[] = [
    'complementary',
    'analogous',
    'triadic',
    'split-complementary',
    'tetradic',
  ]
  return modes.map((mode) => generatePalette(baseHex, mode))
}

/** All available harmony modes with labels */
export const harmonyModes: { value: HarmonyMode; label: string }[] = [
  { value: 'complementary', label: 'Complementary' },
  { value: 'analogous', label: 'Analogous' },
  { value: 'triadic', label: 'Triadic' },
  { value: 'split-complementary', label: 'Split-Complementary' },
  { value: 'tetradic', label: 'Tetradic' },
]

/** WCAG contrast ratio calculation and compliance checking */

import type { RGB } from './color'

export type WCAGLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  normalText: WCAGLevel
  largeText: WCAGLevel
}

/** Convert an sRGB channel value (0-255) to linear RGB */
const linearize = (channel: number): number => {
  const c = channel / 255
  return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4)
}

/** Calculate relative luminance per WCAG 2.1 spec */
export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * linearize(rgb.r) + 0.7152 * linearize(rgb.g) + 0.0722 * linearize(rgb.b)

/** Calculate contrast ratio between two RGB colors (returns ratio >= 1) */
export const contrastRatio = (color1: RGB, color2: RGB): number => {
  const l1 = relativeLuminance(color1)
  const l2 = relativeLuminance(color2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

/** Determine WCAG compliance level for a given contrast ratio */
const wcagLevel = (ratio: number, aaThreshold: number, aaaThreshold: number): WCAGLevel => {
  if (ratio >= aaaThreshold) return 'AAA'
  if (ratio >= aaThreshold) return 'AA'
  return 'Fail'
}

/** Full contrast check between two RGB colors */
export const checkContrast = (color1: RGB, color2: RGB): ContrastResult => {
  const ratio = contrastRatio(color1, color2)
  return {
    ratio: Math.round(ratio * 100) / 100,
    normalText: wcagLevel(ratio, 4.5, 7),
    largeText: wcagLevel(ratio, 3, 4.5),
  }
}

