  const palette = generatePalette(baseHex, 'complementary')
  return {
    baseHex,
    mode: 'complementary',
    palette,
    selectedIndices: null,
    contrastResult: null,
  }
}

/** Update the base color and regenerate the palette */
export const updateBaseColor = (state: AppState, hex: string): AppState => {
  if (!isValidHex(hex)) return state
  const normalized = hex.startsWith('#') ? hex : `#${hex}`
  const palette = generatePalette(normalized, state.mode)
  return {
    ...state,
    baseHex: normalized,
    palette,
    selectedIndices: null,
    contrastResult: null,
  }
}

/** Change the harmony mode and regenerate the palette */
export const updateHarmonyMode = (state: AppState, mode: HarmonyMode): AppState => {
  const palette = generatePalette(state.baseHex, mode)
  return {
    ...state,
    mode,
    palette,
    selectedIndices: null,
    contrastResult: null,
  }
}

/** Select a color for contrast comparison */
export const selectColorForContrast = (state: AppState, index: number): AppState => {
  const { palette, selectedIndices } = state
  if (index < 0 || index >= palette.colors.length) return state

  // If no selection yet, set first
  if (selectedIndices === null) {
    return { ...state, selectedIndices: [index, index], contrastResult: null }
  }

  // If clicking the same as first, deselect
  if (selectedIndices[0] === index && selectedIndices[1] === index) {
    return { ...state, selectedIndices: null, contrastResult: null }
  }

  // Set second selection and compute contrast
  const pair: [number, number] =
    selectedIndices[1] === selectedIndices[0] ? [selectedIndices[0], index] : [index, index]

  if (pair[0] === pair[1]) {
    return { ...state, selectedIndices: pair, contrastResult: null }
  }

  const color1 = palette.colors[pair[0]]
  const color2 = palette.colors[pair[1]]
  const contrastResult = checkContrast(color1.rgb, color2.rgb)

  return { ...state, selectedIndices: pair, contrastResult }
}

/** Render the current state to HTML */
export const render = (state: AppState): string =>
  renderPage(state.baseHex, state.palette, state.selectedIndices, state.contrastResult)

/** Serve the application */
export const serve = (port = 3000) => {
  let state = createInitialState()

  return Bun.serve({
    port,
    fetch: (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' && req.method === 'GET') {
        return new Response(render(state), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/color' && req.method === 'POST') {
        const hex = url.searchParams.get('hex')
        if (hex) state = updateBaseColor(state, hex)
        return new Response(render(state), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/mode' && req.method === 'POST') {
        const mode = url.searchParams.get('mode') as HarmonyMode
        if (mode) state = updateHarmonyMode(state, mode)
        return new Response(render(state), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/select' && req.method === 'POST') {
        const index = parseInt(url.searchParams.get('index') ?? '', 10)
        if (!isNaN(index)) state = selectColorForContrast(state, index)
        return new Response(render(state), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/palettes' && req.method === 'GET') {
        const palettes = generateAllPalettes(state.baseHex)
        return Response.json(palettes)
      }

      return new Response('Not Found', { status: 404 })
    },
  })
}

