import type { GalleryFilters, SortMode } from './types'
import { filterAndSortProjects, getAllTags, getProjectById } from './store'
import { renderToHTML } from './render'

const parseFilters = (url: URL): GalleryFilters => ({
  search: url.searchParams.get('search') ?? '',
  tag: url.searchParams.get('tag') || null,
  sort: (url.searchParams.get('sort') as SortMode) ?? 'date-desc',
})

export const handleGalleryRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (url.pathname === '/api/projects') {
    const filters = parseFilters(url)
    const projects = await filterAndSortProjects(filters)
    return new Response(JSON.stringify(projects), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (url.pathname === '/api/tags') {
    const tags = await getAllTags()
    return new Response(JSON.stringify(tags), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (url.pathname.startsWith('/api/projects/')) {
    const id = url.pathname.split('/').pop()
    if (!id) {
      return new Response(JSON.stringify({ error: 'Missing project ID' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' },
      })
    }
    const project = await getProjectById(id)
    if (!project) {
      return new Response(JSON.stringify({ error: 'Project not found' }), {
        status: 404,
        headers: { 'Content-Type': 'application/json' },
      })
    }
    return new Response(JSON.stringify(project), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (url.pathname === '/' || url.pathname === '/gallery') {
    const filters = parseFilters(url)
    const [projects, allTags] = await Promise.all([
      filterAndSortProjects(filters),
      getAllTags(),
    ])

    const detailId = url.searchParams.get('detail')
    const detail = detailId ? await getProjectById(detailId) : undefined

    const html = renderToHTML(projects, allTags, filters, detail ?? undefined)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  return new Response('Not Found', { status: 404 })
}

