export type ToolKind = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser'

export type Point = {
  x: number
  y: number
}

export type Stroke = {
  id: string
  tool: ToolKind
  points: Point[]
  color: string
  size: number
  start: Point
  end: Point
}

export type Layer = {
  id: string
  name: string
  visible: boolean
  strokes: Stroke[]
  thumbnail: string
}

export type CanvasState = {
  layers: Layer[]
  activeLayerId: string
  history: HistoryEntry[]
  historyIndex: number
  width: number
  height: number
}

export type HistoryEntry = {
  layerSnapshots: Layer[]
}

export type DrawingFile = {
  version: number
  createdAt: string
  updatedAt: string
  state: CanvasState
}

export type ToolbarState = {
  activeTool: ToolKind
  color: string
  brushSize: number
}

import type { Layer, Stroke } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter += 1
  return {
    id: `layer-${Date.now()}-${layerCounter}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    strokes: [],
    thumbnail: '',
  }
}

export const addStrokeToLayer = (layer: Layer, stroke: Stroke): Layer => ({
  ...layer,
  strokes: [...layer.strokes, stroke],
})

export const removeLastStrokeFromLayer = (layer: Layer): Layer => ({
  ...layer,
  strokes: layer.strokes.slice(0, -1),
})

export const toggleLayerVisibility = (layer: Layer): Layer => ({
  ...layer,
  visible: !layer.visible,
})

export const cloneLayer = (layer: Layer): Layer => ({
  ...layer,
  id: layer.id,
  strokes: layer.strokes.map((s) => ({ ...s })),
})

export const cloneLayers = (layers: Layer[]): Layer[] =>
  layers.map(cloneLayer)

import type { Point, Stroke, ToolKind } from './types'

let strokeCounter = 0

export const createStrokeId = (): string => {
  strokeCounter += 1
  return `stroke-${Date.now()}-${strokeCounter}`
}

export const createStroke = (
  tool: ToolKind,
  start: Point,
  color: string,
  size: number,
): Stroke => ({
  id: createStrokeId(),
  tool,
  points: [start],
  color,
  size,
  start,
  end: start,
})

export const addPointToStroke = (stroke: Stroke, point: Point): Stroke => ({
  ...stroke,
  points: [...stroke.points, point],
  end: point,
})

export const finalizeStroke = (stroke: Stroke, end: Point): Stroke => ({
  ...stroke,
  end,
})

export const renderStrokeToContext = (
  ctx: CanvasRenderingContext2D,
  stroke: Stroke,
): void => {
  ctx.save()

  if (stroke.tool === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out'
    ctx.strokeStyle = 'rgba(0,0,0,1)'
  } else {
    ctx.globalCompositeOperation = 'source-over'
    ctx.strokeStyle = stroke.color
  }

  ctx.lineWidth = stroke.size
  ctx.lineCap = 'round'
  ctx.lineJoin = 'round'

  switch (stroke.tool) {
    case 'pen':
    case 'eraser': {
      ctx.beginPath()
      const pts = stroke.points
      if (pts.length === 0) break
      ctx.moveTo(pts[0].x, pts[0].y)
      for (let i = 1; i < pts.length; i++) {
        ctx.lineTo(pts[i].x, pts[i].y)
      }
      ctx.stroke()
      break
    }
    case 'line': {
      ctx.beginPath()
      ctx.moveTo(stroke.start.x, stroke.start.y)
      ctx.lineTo(stroke.end.x, stroke.end.y)
      ctx.stroke()
      break
    }
    case 'rectangle': {
      const x = Math.min(stroke.start.x, stroke.end.x)
      const y = Math.min(stroke.start.y, stroke.end.y)
      const w = Math.abs(stroke.end.x - stroke.start.x)
      const h = Math.abs(stroke.end.y - stroke.start.y)
      ctx.strokeRect(x, y, w, h)
      break
    }
    case 'circle': {
      const cx = (stroke.start.x + stroke.end.x) / 2
      const cy = (stroke.start.y + stroke.end.y) / 2
      const rx = Math.abs(stroke.end.x - stroke.start.x) / 2
      const ry = Math.abs(stroke.end.y - stroke.start.y) / 2
      ctx.beginPath()
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      ctx.stroke()
      break
    }
  }

  ctx.restore()
}

import type { CanvasState, HistoryEntry, Layer, Stroke } from './types'
import { createLayer, addStrokeToLayer, cloneLayers } from './layers'

const DEFAULT_WIDTH = 800
const DEFAULT_HEIGHT = 600
const MAX_HISTORY = 50

export const createInitialState = (
  width = DEFAULT_WIDTH,
  height = DEFAULT_HEIGHT,
): CanvasState => {
  const baseLayer = createLayer('Background')
  const snapshot: HistoryEntry = { layerSnapshots: cloneLayers([baseLayer]) }
  return {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    history: [snapshot],
    historyIndex: 0,
    width,
    height,
  }
}

export const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId)

const pushHistory = (state: CanvasState): CanvasState => {
  const snapshot: HistoryEntry = { layerSnapshots: cloneLayers(state.layers) }
  const trimmedHistory = state.history.slice(0, state.historyIndex + 1)
  const history = [...trimmedHistory, snapshot].slice(-MAX_HISTORY)
  return {
    ...state,
    history,
    historyIndex: history.length - 1,
  }
}

export const addStroke = (state: CanvasState, stroke: Stroke): CanvasState => {
  const layers = state.layers.map((layer) =>
    layer.id === state.activeLayerId ? addStrokeToLayer(layer, stroke) : layer,
  )
  return pushHistory({ ...state, layers })
}

export const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name)
  const updated = {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
  return pushHistory(updated)
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const layers = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId =
    state.activeLayerId === layerId ? layers[layers.length - 1].id : state.activeLayerId
  return pushHistory({ ...state, layers, activeLayerId })
}

export const toggleLayerVisibility = (
  state: CanvasState,
  layerId: string,
): CanvasState => {
  const layers = state.layers.map((l) =>
    l.id === layerId ? { ...l, visible: !l.visible } : l,
  )
  return { ...state, layers }
}

export const setActiveLayer = (
  state: CanvasState,
  layerId: string,
): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

export const clearCanvas = (state: CanvasState): CanvasState => {
  const layers = state.layers.map((layer) => ({ ...layer, strokes: [] }))
  return pushHistory({ ...state, layers })
}

export const undo = (state: CanvasState): CanvasState => {
  if (state.historyIndex <= 0) return state
  const newIndex = state.historyIndex - 1
  const snapshot = state.history[newIndex]
  return {
    ...state,
    layers: cloneLayers(snapshot.layerSnapshots),
    historyIndex: newIndex,
    activeLayerId:
      snapshot.layerSnapshots.find((l) => l.id === state.activeLayerId)?.id ??
      snapshot.layerSnapshots[snapshot.layerSnapshots.length - 1].id,
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.historyIndex >= state.history.length - 1) return state
  const newIndex = state.historyIndex + 1
  const snapshot = state.history[newIndex]
  return {
    ...state,
    layers: cloneLayers(snapshot.layerSnapshots),
    historyIndex: newIndex,
    activeLayerId:
      snapshot.layerSnapshots.find((l) => l.id === state.activeLayerId)?.id ??
      snapshot.layerSnapshots[snapshot.layerSnapshots.length - 1].id,
  }
}

import type { CanvasState, DrawingFile } from './types'
import { createInitialState } from './canvas-state'
import { cloneLayers } from './layers'

const DATA_DIR = './data'

export const saveDrawing = async (
  state: CanvasState,
  filename: string,
): Promise<void> => {
  const drawing: DrawingFile = {
    version: 1,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    state: {
      ...state,
      history: [],
      historyIndex: 0,
    },
  }
  const path = `${DATA_DIR}/${filename}.json`
  await Bun.write(path, JSON.stringify(drawing, null, 2))
}

export const loadDrawing = async (
  filename: string,
): Promise<CanvasState | null> => {
  const path = `${DATA_DIR}/${filename}.json`
  const file = Bun.file(path)
  const exists = await file.exists()
  if (!exists) return null

  const text = await file.text()
  const drawing: DrawingFile = JSON.parse(text)
  const state = drawing.state
  return {
    ...state,
    layers: cloneLayers(state.layers),
    history: [{ layerSnapshots: cloneLayers(state.layers) }],
    historyIndex: 0,
  }
}

export const listDrawings = async (): Promise<string[]> => {
  const glob = new Bun.Glob('*.json')
  const results: string[] = []
  for await (const entry of glob.scan({ cwd: DATA_DIR })) {
    results.push(entry.replace(/\.json$/, ''))
  }
  return results
}

export const deleteDrawing = async (filename: string): Promise<boolean> => {
  const path = `${DATA_DIR}/${filename}.json`
  const file = Bun.file(path)
  const exists = await file.exists()
  if (!exists) return false
  const { unlinkSync } = await import('node:fs')
  unlinkSync(path)
  return true
}

