const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

const renderToolButton = (
  tool: ToolKind,
  activeTool: ToolKind,
): ReturnType<typeof h> => {
  const isActive = tool === activeTool
  const combinedStyle = {
    ...styles.toolButton,
    ...(isActive ? styles.toolButtonActive : {}),
  }
  const iconPath = toolIcons[tool]
  return h(
    'button',
    {
      style: styleToStr(combinedStyle),
      title: tool.charAt(0).toUpperCase() + tool.slice(1),
      'p-trigger': `selectTool:${tool}`,
    },
    h(
      'svg',
      { width: '20', height: '20', viewBox: '0 0 24 24', fill: 'none' },
      tool === 'line'
        ? h('line', {
            x1: '4',
            y1: '20',
            x2: '20',
            y2: '4',
            stroke: 'currentColor',
            'stroke-width': '2',
            'stroke-linecap': 'round',
          })
        : h('path', {
            d: iconPath,
            fill: tool === 'eraser' ? 'none' : 'currentColor',
            stroke: tool === 'eraser' ? 'currentColor' : 'none',
            'stroke-width': tool === 'eraser' ? '1.5' : '0',
          }),
    ),
  )
}

const renderLayerItem = (
  layer: Layer,
  isActive: boolean,
): ReturnType<typeof h> => {
  const itemStyle = {
    ...styles.layerItem,
    ...(isActive ? styles.layerItemActive : {}),
  }
  return h(
    'div',
    {
      style: styleToStr(itemStyle),
      'p-trigger': `selectLayer:${layer.id}`,
    },
    layer.thumbnail
      ? h('img', {
          src: layer.thumbnail,
          style: styleToStr(styles.layerThumbnail),
          alt: layer.name,
        })
      : h('div', { style: styleToStr(styles.layerThumbnail) }),
    h('span', { style: styleToStr(styles.layerName) }, layer.name),
    h(
      'button',
