import type { CanvasState, ToolbarState, Point, Stroke, ToolKind } from './types'
import {
  createInitialState,
  getActiveLayer,
  addStroke,
  addLayer,
  removeLayer,
  toggleLayerVisibility,
  setActiveLayer,
  clearCanvas,
  undo,
  redo,
} from './canvas-state'
import { createStroke, addPointToStroke, finalizeStroke, renderStrokeToContext } from './tools'
import { saveDrawing, loadDrawing, listDrawings } from './persistence'
import { renderApp } from './renderer'

export type DrawingCanvas = {
  getState: () => CanvasState
  getToolbar: () => ToolbarState
  setTool: (tool: ToolKind) => void
  setColor: (color: string) => void
  setBrushSize: (size: number) => void
  beginStroke: (point: Point) => void
  continueStroke: (point: Point) => void
  endStroke: (point: Point) => void
  performUndo: () => void
  performRedo: () => void
  performClear: () => void
  addNewLayer: (name?: string) => void
  deleteLayer: (layerId: string) => void
  toggleLayer: (layerId: string) => void
  selectLayer: (layerId: string) => void
  save: (filename: string) => Promise<void>
  load: (filename: string) => Promise<boolean>
  list: () => Promise<string[]>
  render: () => ReturnType<typeof renderApp>
  renderAllLayers: (ctx: CanvasRenderingContext2D) => void
  canUndo: () => boolean
  canRedo: () => boolean
}

export const createDrawingCanvas = (
  width = 800,
  height = 600,
): DrawingCanvas => {
  let canvasState: CanvasState = createInitialState(width, height)
  let toolbarState: ToolbarState = {
    activeTool: 'pen',
    color: '#000000',
    brushSize: 4,
  }
  let currentStroke: Stroke | null = null

  const renderAllLayers = (ctx: CanvasRenderingContext2D): void => {
    ctx.clearRect(0, 0, canvasState.width, canvasState.height)
    for (const layer of canvasState.layers) {
      if (!layer.visible) continue
      for (const stroke of layer.strokes) {
        renderStrokeToContext(ctx, stroke)
      }
    }
    // Render in-progress stroke
    if (currentStroke) {
      renderStrokeToContext(ctx, currentStroke)
    }
  }

  const instance: DrawingCanvas = {
    getState: () => canvasState,
    getToolbar: () => toolbarState,

    setTool: (tool) => {
      toolbarState = { ...toolbarState, activeTool: tool }
    },

    setColor: (color) => {
      toolbarState = { ...toolbarState, color }
    },

    setBrushSize: (size) => {
      toolbarState = { ...toolbarState, brushSize: Math.max(1, Math.min(50, size)) }
    },

    beginStroke: (point) => {
      const activeLayer = getActiveLayer(canvasState)
      if (!activeLayer?.visible) return
      currentStroke = createStroke(
        toolbarState.activeTool,
        point,
        toolbarState.activeTool === 'eraser' ? '#000000' : toolbarState.color,
        toolbarState.brushSize,
      )
    },

    continueStroke: (point) => {
      if (!currentStroke) return
      const tool = currentStroke.tool
      if (tool === 'pen' || tool === 'eraser') {
        currentStroke = addPointToStroke(currentStroke, point)
      } else {
        currentStroke = finalizeStroke(currentStroke, point)
      }
    },

    endStroke: (point) => {
      if (!currentStroke) return
      const finalized = finalizeStroke(currentStroke, point)
      canvasState = addStroke(canvasState, finalized)
      currentStroke = null
    },

    performUndo: () => {
      canvasState = undo(canvasState)
    },

    performRedo: () => {
      canvasState = redo(canvasState)
    },

    performClear: () => {
      canvasState = clearCanvas(canvasState)
    },

    addNewLayer: (name) => {
      canvasState = addLayer(canvasState, name)
    },

    deleteLayer: (layerId) => {
      canvasState = removeLayer(canvasState, layerId)
    },

    toggleLayer: (layerId) => {
      canvasState = toggleLayerVisibility(canvasState, layerId)
    },

    selectLayer: (layerId) => {
      canvasState = setActiveLayer(canvasState, layerId)
    },

    save: async (filename) => {
      await saveDrawing(canvasState, filename)
    },

    load: async (filename) => {
      const loaded = await loadDrawing(filename)
      if (!loaded) return false
      canvasState = loaded
      return true
    },

    list: () => listDrawings(),

    render: () => renderApp(canvasState, toolbarState),

    renderAllLayers,

    canUndo: () => canvasState.historyIndex > 0,

    canRedo: () => canvasState.historyIndex < canvasState.history.length - 1,
  }

  return instance
}

