export type { CanvasState, ToolbarState, ToolKind, Layer, Stroke, Point, DrawingFile } from './types'

import type { ToolKind, Point } from './types'
import { createDrawingCanvas } from './index'

/**
 * Client-side entry point that wires up DOM events to the drawing canvas module.
 * Attach to a page by calling `initCanvas(containerEl)`.
 */
export const initCanvas = (container: HTMLElement, width = 800, height = 600): void => {
  const canvas = createDrawingCanvas(width, height)

  const rerender = (): void => {
    const vdom = canvas.render()
    // In a real plaited integration this would diff/patch;
    // here we serialize to illustrate the wiring
    container.innerHTML = ''
    container.appendChild(vdom as unknown as Node)
    bindEvents()
    redrawCanvas()
  }

  const redrawCanvas = (): void => {
    const el = container.querySelector('[p-target="drawing-canvas"]') as HTMLCanvasElement | null
    if (!el) return
    const ctx = el.getContext('2d')
    if (!ctx) return
    canvas.renderAllLayers(ctx)
  }

  const getCanvasPoint = (e: PointerEvent): Point => {
    const el = container.querySelector('[p-target="drawing-canvas"]') as HTMLCanvasElement
    const rect = el.getBoundingClientRect()
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    }
  }

  const bindEvents = (): void => {
    // Tool buttons
    container.querySelectorAll<HTMLElement>('[p-trigger^="selectTool:"]').forEach((btn) => {
      const tool = btn.getAttribute('p-trigger')?.split(':')[1] as ToolKind
      btn.addEventListener('click', () => {
        canvas.setTool(tool)
        rerender()
      })
    })

    // Color picker
    const colorInput = container.querySelector<HTMLInputElement>('[p-trigger="changeColor"]')
    colorInput?.addEventListener('input', (e) => {
      canvas.setColor((e.target as HTMLInputElement).value)
    })

    // Brush size
    const sizeInput = container.querySelector<HTMLInputElement>('[p-trigger="changeBrushSize"]')
    sizeInput?.addEventListener('input', (e) => {
      canvas.setBrushSize(Number((e.target as HTMLInputElement).value))
      const sizeDisplay = sizeInput.nextElementSibling
      if (sizeDisplay) sizeDisplay.textContent = `${(e.target as HTMLInputElement).value}px`
    })

    // Canvas drawing
    const canvasEl = container.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
    if (canvasEl) {
      let isDrawing = false

      canvasEl.addEventListener('pointerdown', (e) => {
        isDrawing = true
        canvasEl.setPointerCapture(e.pointerId)
        canvas.beginStroke(getCanvasPoint(e))
        redrawCanvas()
      })

      canvasEl.addEventListener('pointermove', (e) => {
        if (!isDrawing) return
        canvas.continueStroke(getCanvasPoint(e))
        redrawCanvas()
      })

      canvasEl.addEventListener('pointerup', (e) => {
        if (!isDrawing) return
        isDrawing = false
        canvas.endStroke(getCanvasPoint(e))
        rerender()
      })
    }

    // Undo / Redo / Clear
    container.querySelector('[p-trigger="undo"]')?.addEventListener('click', () => {
      canvas.performUndo()
      rerender()
    })
    container.querySelector('[p-trigger="redo"]')?.addEventListener('click', () => {
      canvas.performRedo()
      rerender()
    })
    container.querySelector('[p-trigger="clear"]')?.addEventListener('click', () => {
      canvas.performClear()
      rerender()
    })

    // Save PNG
    container.querySelector('[p-trigger="save"]')?.addEventListener('click', () => {
      const el = container.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
      if (!el) return
      const dataUrl = el.toDataURL('image/png')
      const link = document.createElement('a')
      link.download = `drawing-${Date.now()}.png`
      link.href = dataUrl
      link.click()
    })

    // Load PNG
    container.querySelector('[p-trigger="load"]')?.addEventListener('click', () => {
      const input = document.createElement('input')
      input.type = 'file'
      input.accept = 'image/png'
      input.addEventListener('change', () => {
        const file = input.files?.[0]
        if (!file) return
        const reader = new FileReader()
        reader.addEventListener('load', () => {
          const img = new Image()
          img.addEventListener('load', () => {
            const el = container.querySelector<HTMLCanvasElement>('[p-target="drawing-canvas"]')
            if (!el) return
            const ctx = el.getContext('2d')
            if (!ctx) return
            ctx.drawImage(img, 0, 0)
          })
          img.src = reader.result as string
        })
        reader.readAsDataURL(file)
      })
      input.click()
    })

    // Save project (JSON)
    container.querySelector('[p-trigger="saveProject"]')?.addEventListener('click', async () => {
      const name = globalThis.prompt?.('Project name:') ?? `project-${Date.now()}`
      if (name) await canvas.save(name)
    })

    // Layer selection
    container.querySelectorAll<HTMLElement>('[p-trigger^="selectLayer:"]').forEach((el) => {
      const layerId = el.getAttribute('p-trigger')?.split(':')[1]
      if (!layerId) return
      el.addEventListener('click', (e) => {
        if ((e.target as HTMLElement).closest('[p-trigger^="toggleLayer:"]')) return
        canvas.selectLayer(layerId)
        rerender()
      })
    })

    // Layer visibility toggle
    container.querySelectorAll<HTMLElement>('[p-trigger^="toggleLayer:"]').forEach((el) => {
      const layerId = el.getAttribute('p-trigger')?.split(':')[1]
      if (!layerId) return
      el.addEventListener('click', () => {
        canvas.toggleLayer(layerId)
        rerender()
      })
    })

    // Add layer
    container.querySelector('[p-trigger="addLayer"]')?.addEventListener('click', () => {
      canvas.addNewLayer()
      rerender()
    })
  }

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if (e.ctrlKey || e.metaKey) {
      if (e.key === 'z' && !e.shiftKey) {
        e.preventDefault()
        canvas.performUndo()
        rerender()
      } else if ((e.key === 'z' && e.shiftKey) || e.key === 'y') {
        e.preventDefault()
        canvas.performRedo()
        rerender()
      }
    }
  })

  // Initial render
  rerender()
}

{
  "name": "@node/playlist-manager",
  "version": "1.0.0",
  "description": "Music playlist manager with playback controls, drag-to-reorder, shuffle, and repeat",
  "modnet": {
    "contentType": "entertainment",
    "structure": "list",
