  }
}

import type { AppState, Playlist, PlayerState } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const defaultPlayerState: PlayerState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  shuffle: false,
  repeat: 'off',
  progressSeconds: 0,
  shuffleOrder: [],
}

const defaultState: AppState = {
  playlists: [],
  player: defaultPlayerState,
}

export const loadState = async (): Promise<AppState> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { ...defaultState }
  const text = await file.text()
  return JSON.parse(text) as AppState
}

export const saveState = async (state: AppState): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(state, null, 2))
}

export const resetPlayerState = (): PlayerState => ({ ...defaultPlayerState, shuffleOrder: [] })

import type { AppState, Playlist, Song } from './types'
import { loadState, saveState } from './store'

const generateId = (): string => crypto.randomUUID()

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const state = await loadState()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId(),
    name,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  state.playlists.push(playlist)
  await saveState(state)
  return playlist
}

export const deletePlaylist = async (playlistId: string): Promise<void> => {
  const state = await loadState()
  state.playlists = state.playlists.filter((p) => p.id !== playlistId)
  if (state.player.currentPlaylistId === playlistId) {
    state.player.currentPlaylistId = null
    state.player.currentSongIndex = 0
    state.player.isPlaying = false
    state.player.progressSeconds = 0
    state.player.shuffleOrder = []
  }
  await saveState(state)
}

export const renamePlaylist = async (playlistId: string, name: string): Promise<void> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) throw new Error(`Playlist ${playlistId} not found`)
  playlist.name = name
  playlist.updatedAt = new Date().toISOString()
  await saveState(state)
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) throw new Error(`Playlist ${playlistId} not found`)
  const newSong: Song = { id: generateId(), ...song }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  await saveState(state)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<void> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) throw new Error(`Playlist ${playlistId} not found`)
  const songIndex = playlist.songs.findIndex((s) => s.id === songId)
  if (songIndex === -1) throw new Error(`Song ${songId} not found`)
  playlist.songs.splice(songIndex, 1)
  playlist.updatedAt = new Date().toISOString()
  if (state.player.currentPlaylistId === playlistId) {
    if (state.player.currentSongIndex >= playlist.songs.length) {
      state.player.currentSongIndex = Math.max(0, playlist.songs.length - 1)
    }
    if (playlist.songs.length === 0) {
      state.player.isPlaying = false
      state.player.progressSeconds = 0
    }
  }
  await saveState(state)
}

export const reorderSong = async (
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<void> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) throw new Error(`Playlist ${playlistId} not found`)
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) throw new Error('Invalid fromIndex')
  if (toIndex < 0 || toIndex >= playlist.songs.length) throw new Error('Invalid toIndex')
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  playlist.updatedAt = new Date().toISOString()
  if (state.player.currentPlaylistId === playlistId) {
    if (state.player.currentSongIndex === fromIndex) {
      state.player.currentSongIndex = toIndex
    } else if (fromIndex < state.player.currentSongIndex && toIndex >= state.player.currentSongIndex) {
      state.player.currentSongIndex--
    } else if (fromIndex > state.player.currentSongIndex && toIndex <= state.player.currentSongIndex) {
      state.player.currentSongIndex++
    }
  }
  await saveState(state)
}

export const getPlaylist = async (playlistId: string): Promise<Playlist | undefined> => {
  const state = await loadState()
  return state.playlists.find((p) => p.id === playlistId)
}

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  const state = await loadState()
  return state.playlists
}

import type { AppState, PlayerState, RepeatMode, Song } from './types'
import { loadState, saveState } from './store'

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

const getCurrentPlaylistSongs = (state: AppState): Song[] => {
  const playlist = state.playlists.find((p) => p.id === state.player.currentPlaylistId)
  return playlist?.songs ?? []
}

export const play = async (playlistId: string, songIndex?: number): Promise<PlayerState> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) throw new Error(`Playlist ${playlistId} not found`)
  if (playlist.songs.length === 0) throw new Error('Playlist is empty')
  const index = songIndex ?? 0
  if (index < 0 || index >= playlist.songs.length) throw new Error('Invalid song index')
  state.player.currentPlaylistId = playlistId
  state.player.currentSongIndex = index
  state.player.isPlaying = true
  state.player.progressSeconds = 0
  if (state.player.shuffle) {
    state.player.shuffleOrder = generateShuffleOrder(playlist.songs.length, index)
  }
  await saveState(state)
  return state.player
}

export const pause = async (): Promise<PlayerState> => {
  const state = await loadState()
  state.player.isPlaying = false
  await saveState(state)
  return state.player
}

export const resume = async (): Promise<PlayerState> => {
  const state = await loadState()
  if (!state.player.currentPlaylistId) throw new Error('No playlist loaded')
  state.player.isPlaying = true
  await saveState(state)
  return state.player
}

export const togglePlayPause = async (): Promise<PlayerState> => {
  const state = await loadState()
  if (!state.player.currentPlaylistId) throw new Error('No playlist loaded')
  state.player.isPlaying = !state.player.isPlaying
  await saveState(state)
  return state.player
}

export const skipNext = async (): Promise<PlayerState> => {
  const state = await loadState()
  const songs = getCurrentPlaylistSongs(state)
  if (songs.length === 0) return state.player

  if (state.player.repeat === 'one') {
    state.player.progressSeconds = 0
    await saveState(state)
    return state.player
  }

  if (state.player.shuffle && state.player.shuffleOrder.length > 0) {
    const currentShuffleIdx = state.player.shuffleOrder.indexOf(state.player.currentSongIndex)
    const nextShuffleIdx = currentShuffleIdx + 1
    if (nextShuffleIdx < state.player.shuffleOrder.length) {
      state.player.currentSongIndex = state.player.shuffleOrder[nextShuffleIdx]
    } else if (state.player.repeat === 'all') {
      state.player.shuffleOrder = generateShuffleOrder(songs.length, state.player.currentSongIndex)
      state.player.currentSongIndex = state.player.shuffleOrder[0]
    } else {
      state.player.isPlaying = false
      state.player.currentSongIndex = state.player.shuffleOrder[0]
    }
  } else {
    const nextIndex = state.player.currentSongIndex + 1
    if (nextIndex < songs.length) {
      state.player.currentSongIndex = nextIndex
    } else if (state.player.repeat === 'all') {
      state.player.currentSongIndex = 0
    } else {
      state.player.isPlaying = false
      state.player.currentSongIndex = 0
    }
  }

  state.player.progressSeconds = 0
  await saveState(state)
  return state.player
}

export const skipPrevious = async (): Promise<PlayerState> => {
  const state = await loadState()
  const songs = getCurrentPlaylistSongs(state)
  if (songs.length === 0) return state.player

  if (state.player.progressSeconds > 3) {
    state.player.progressSeconds = 0
    await saveState(state)
    return state.player
  }

  if (state.player.shuffle && state.player.shuffleOrder.length > 0) {
    const currentShuffleIdx = state.player.shuffleOrder.indexOf(state.player.currentSongIndex)
    const prevShuffleIdx = currentShuffleIdx - 1
    if (prevShuffleIdx >= 0) {
      state.player.currentSongIndex = state.player.shuffleOrder[prevShuffleIdx]
    } else if (state.player.repeat === 'all') {
      state.player.currentSongIndex = state.player.shuffleOrder[state.player.shuffleOrder.length - 1]
    }
  } else {
    const prevIndex = state.player.currentSongIndex - 1
    if (prevIndex >= 0) {
      state.player.currentSongIndex = prevIndex
    } else if (state.player.repeat === 'all') {
      state.player.currentSongIndex = songs.length - 1
    }
  }

  state.player.progressSeconds = 0
  await saveState(state)
  return state.player
}

export const toggleShuffle = async (): Promise<PlayerState> => {
  const state = await loadState()
  state.player.shuffle = !state.player.shuffle
  if (state.player.shuffle) {
    const songs = getCurrentPlaylistSongs(state)
    if (songs.length > 0) {
      state.player.shuffleOrder = generateShuffleOrder(songs.length, state.player.currentSongIndex)
    }
  } else {
    state.player.shuffleOrder = []
  }
  await saveState(state)
  return state.player
}

export const cycleRepeat = async (): Promise<PlayerState> => {
  const state = await loadState()
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(state.player.repeat)
  state.player.repeat = modes[(currentIdx + 1) % modes.length]
  await saveState(state)
  return state.player
}

export const seek = async (seconds: number): Promise<PlayerState> => {
  const state = await loadState()
  state.player.progressSeconds = Math.max(0, seconds)
  await saveState(state)
  return state.player
}

export const getPlayerState = async (): Promise<PlayerState> => {
  const state = await loadState()
  return state.player
}

export const getNowPlaying = async (): Promise<Song | null> => {
  const state = await loadState()
  if (!state.player.currentPlaylistId) return null
  const songs = getCurrentPlaylistSongs(state)
  return songs[state.player.currentSongIndex] ?? null
}

