} from './playlist'
import {
  play,
  pause,
  resume,
  togglePlayPause,
  skipNext,
  skipPrevious,
  toggleShuffle,
  cycleRepeat,
  seek,
  getPlayerState,
  getNowPlaying,
} from './player'
import { renderApp } from './render'
import type { Song } from './types'

export type ActionResult = {
  ok: boolean
  data?: unknown
  error?: string
}

export type Action =
  | { type: 'create-playlist'; name: string }
  | { type: 'delete-playlist'; playlistId: string }
  | { type: 'rename-playlist'; playlistId: string; name: string }
  | { type: 'add-song'; playlistId: string; song: Omit<Song, 'id'> }
  | { type: 'remove-song'; playlistId: string; songId: string }
  | { type: 'reorder-song'; playlistId: string; fromIndex: number; toIndex: number }
  | { type: 'play'; playlistId: string; songIndex?: number }
  | { type: 'pause' }
  | { type: 'resume' }
  | { type: 'toggle-play' }
  | { type: 'skip-next' }
  | { type: 'skip-previous' }
  | { type: 'toggle-shuffle' }
  | { type: 'cycle-repeat' }
  | { type: 'seek'; seconds: number }

const handleAction = async (action: Action): Promise<ActionResult> => {
  try {
    switch (action.type) {
      case 'create-playlist': {
        const pl = await createPlaylist(action.name)
        return { ok: true, data: pl }
      }
      case 'delete-playlist': {
        await deletePlaylist(action.playlistId)
        return { ok: true }
      }
      case 'rename-playlist': {
        await renamePlaylist(action.playlistId, action.name)
        return { ok: true }
      }
      case 'add-song': {
        const song = await addSong(action.playlistId, action.song)
        return { ok: true, data: song }
      }
      case 'remove-song': {
        await removeSong(action.playlistId, action.songId)
        return { ok: true }
      }
      case 'reorder-song': {
        await reorderSong(action.playlistId, action.fromIndex, action.toIndex)
        return { ok: true }
      }
      case 'play': {
        const ps = await play(action.playlistId, action.songIndex)
        return { ok: true, data: ps }
      }
      case 'pause': {
        const ps = await pause()
        return { ok: true, data: ps }
      }
      case 'resume': {
        const ps = await resume()
        return { ok: true, data: ps }
      }
      case 'toggle-play': {
        const ps = await togglePlayPause()
        return { ok: true, data: ps }
      }
      case 'skip-next': {
        const ps = await skipNext()
        return { ok: true, data: ps }
      }
      case 'skip-previous': {
        const ps = await skipPrevious()
        return { ok: true, data: ps }
      }
      case 'toggle-shuffle': {
        const ps = await toggleShuffle()
        return { ok: true, data: ps }
      }
      case 'cycle-repeat': {
        const ps = await cycleRepeat()
        return { ok: true, data: ps }
      }
      case 'seek': {
        const ps = await seek(action.seconds)
        return { ok: true, data: ps }
      }
      default:
        return { ok: false, error: 'Unknown action' }
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    return { ok: false, error: message }
  }
}

const render = async (activePlaylistId?: string): Promise<string> => {
  const state = await loadState()
  const ssr = createSSR()
  const tree = renderApp(state, activePlaylistId ?? null)
  return ssr(tree)
}

