import type { ProjectileParams, ProjectileState, RealTimeValues, Vec2 } from './types'

const DEFAULT_PARAMS: ProjectileParams = {
  angle: 45,
  initialVelocity: 20,
  gravity: 9.81,
  height: 0,
}

export const createProjectileParams = (overrides?: Partial<ProjectileParams>): ProjectileParams => ({
  ...DEFAULT_PARAMS,
  ...overrides,
})

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  const vx = params.initialVelocity * Math.cos(angleRad)
  const vy = params.initialVelocity * Math.sin(angleRad)
  const startPos: Vec2 = { x: 0, y: params.height }

  return {
    position: { ...startPos },
    velocity: { x: vx, y: vy },
    acceleration: { x: 0, y: -params.gravity },
    trajectory: [{ ...startPos }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const newVx = state.velocity.x
  const newVy = state.velocity.y - params.gravity * dt

  const newX = state.position.x + state.velocity.x * dt + 0.5 * state.acceleration.x * dt * dt
  const newY = state.position.y + state.velocity.y * dt - 0.5 * params.gravity * dt * dt

  const landed = newY <= 0 && state.position.y >= 0 && state.trajectory.length > 1

  const clampedY = landed ? 0 : newY
  const finalX = landed
    ? state.position.x + state.velocity.x * (state.position.y / (state.position.y - newY)) * dt
    : newX

  const newTrajectory = [...state.trajectory, { x: finalX, y: clampedY }]

  return {
    position: { x: finalX, y: clampedY },
    velocity: landed ? { x: 0, y: 0 } : { x: newVx, y: newVy },
    acceleration: { x: 0, y: landed ? 0 : -params.gravity },
    trajectory: newTrajectory,
    landed,
  }
}

export const getProjectileValues = (
  state: ProjectileState,
  params: ProjectileParams,
): RealTimeValues => {
  const speed = Math.sqrt(state.velocity.x ** 2 + state.velocity.y ** 2)
  const currentAngle = Math.atan2(state.velocity.y, state.velocity.x) * 180 / Math.PI

  const angleRad = (params.angle * Math.PI) / 180
  const maxHeight = params.height + (params.initialVelocity * Math.sin(angleRad)) ** 2 / (2 * params.gravity)
  const timeOfFlight = (params.initialVelocity * Math.sin(angleRad) +
    Math.sqrt((params.initialVelocity * Math.sin(angleRad)) ** 2 + 2 * params.gravity * params.height)) / params.gravity
  const range = params.initialVelocity * Math.cos(angleRad) * timeOfFlight

  return {
    position: `x = ${state.position.x.toFixed(2)} m  |  y = ${state.position.y.toFixed(2)} m`,
    velocity: `vx = ${state.velocity.x.toFixed(2)} m/s  |  vy = ${state.velocity.y.toFixed(2)} m/s  (|v| = ${speed.toFixed(2)} m/s)`,
    acceleration: `ax = 0.00 m/s²  |  ay = ${state.acceleration.y.toFixed(2)} m/s²`,
    extra: {
      'Flight angle': `${currentAngle.toFixed(1)}°`,
      'Max height': `${maxHeight.toFixed(2)} m`,
      'Range': `${range.toFixed(2)} m`,
      'Time of flight': `${timeOfFlight.toFixed(2)} s`,
      'Status': state.landed ? 'Landed' : 'In flight',
    },
  }
}

export const renderProjectileCanvas = (
  state: ProjectileState,
  params: ProjectileParams,
  width: number,
  height: number,
): string => {
  const padding = 50
  const drawW = width - padding * 2
  const drawH = height - padding * 2

  // Calculate analytical range and max height for scaling
  const angleRad = (params.angle * Math.PI) / 180
  const maxHeight = params.height + (params.initialVelocity * Math.sin(angleRad)) ** 2 / (2 * params.gravity)
  const timeOfFlight = (params.initialVelocity * Math.sin(angleRad) +
    Math.sqrt((params.initialVelocity * Math.sin(angleRad)) ** 2 + 2 * params.gravity * params.height)) / params.gravity
  const range = params.initialVelocity * Math.cos(angleRad) * timeOfFlight

  const scaleX = drawW / Math.max(range * 1.15, 1)
  const scaleY = drawH / Math.max(maxHeight * 1.3, 1)
  const scale = Math.min(scaleX, scaleY)

  const toScreenX = (x: number) => padding + x * scale
  const toScreenY = (y: number) => height - padding - y * scale

  const groundY = toScreenY(0)

  // Trajectory path
  const pathPoints = state.trajectory
    .map((p) => `${toScreenX(p.x).toFixed(1)},${toScreenY(p.y).toFixed(1)}`)
    .join(' ')

  // Analytical trajectory (dashed)
  const analyticalPoints: string[] = []
  const steps = 100
  for (let i = 0; i <= steps; i++) {
    const t = (timeOfFlight * i) / steps
    const ax = params.initialVelocity * Math.cos(angleRad) * t
    const ay = params.height + params.initialVelocity * Math.sin(angleRad) * t - 0.5 * params.gravity * t * t
    if (ay >= 0) {
      analyticalPoints.push(`${toScreenX(ax).toFixed(1)},${toScreenY(ay).toFixed(1)}`)
    }
  }

  const ballX = toScreenX(state.position.x)
  const ballY = toScreenY(state.position.y)

  // Velocity arrow scaling
  const vArrowScale = 1.5
  const vEndX = ballX + state.velocity.x * vArrowScale
  const vEndY = ballY - state.velocity.y * vArrowScale

  // Grid lines
  const gridLinesX: string[] = []
  const gridLinesY: string[] = []
  const xStep = Math.pow(10, Math.floor(Math.log10(Math.max(range, 1))))
  const yStep = Math.pow(10, Math.floor(Math.log10(Math.max(maxHeight, 1))))

  for (let x = 0; x <= range * 1.15; x += xStep) {
    const sx = toScreenX(x)
    gridLinesX.push(`<line x1="${sx}" y1="${groundY}" x2="${sx}" y2="${groundY + 5}" stroke="#475569" stroke-width="1"/>
      <text x="${sx}" y="${groundY + 18}" text-anchor="middle" fill="#64748b" font-size="10" font-family="monospace">${x.toFixed(0)}</text>`)
  }
  for (let y = 0; y <= maxHeight * 1.3; y += yStep) {
    const sy = toScreenY(y)
    gridLinesY.push(`<line x1="${padding - 5}" y1="${sy}" x2="${padding}" y2="${sy}" stroke="#475569" stroke-width="1"/>
      <text x="${padding - 8}" y="${sy + 4}" text-anchor="end" fill="#64748b" font-size="10" font-family="monospace">${y.toFixed(0)}</text>`)
  }

  return `
    <svg viewBox="0 0 ${width} ${height}" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <radialGradient id="ballGrad" cx="35%" cy="35%">
          <stop offset="0%" stop-color="#f97316"/>
          <stop offset="100%" stop-color="#c2410c"/>
        </radialGradient>
        <marker id="arrowV" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto">
          <polygon points="0 0, 8 3, 0 6" fill="#22c55e"/>
        </marker>
        <filter id="glow">
          <feGaussianBlur stdDeviation="2" result="blur"/>
          <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>

      <!-- Ground -->
      <rect x="${padding}" y="${groundY}" width="${drawW}" height="${height - groundY}" fill="#0f172a" opacity="0.3"/>
      <line x1="${padding}" y1="${groundY}" x2="${width - padding}" y2="${groundY}" stroke="#334155" stroke-width="2"/>

      <!-- Y axis -->
      <line x1="${padding}" y1="${padding}" x2="${padding}" y2="${groundY}" stroke="#334155" stroke-width="1"/>

      <!-- Grid -->
      ${gridLinesX.join('\n')}
      ${gridLinesY.join('\n')}

      <!-- Analytical trajectory (dashed) -->
      ${analyticalPoints.length > 1 ? `<polyline points="${analyticalPoints.join(' ')}" fill="none" stroke="#475569" stroke-width="1" stroke-dasharray="4,3"/>` : ''}

      <!-- Actual trajectory -->
      ${state.trajectory.length > 1 ? `<polyline points="${pathPoints}" fill="none" stroke="#f97316" stroke-width="2" opacity="0.7"/>` : ''}

      <!-- Launch angle indicator -->
      <line x1="${toScreenX(0)}" y1="${toScreenY(params.height)}"
        x2="${toScreenX(0) + 50 * Math.cos(angleRad)}" y2="${toScreenY(params.height) - 50 * Math.sin(angleRad)}"
        stroke="#fbbf24" stroke-width="1.5" stroke-dasharray="4,2"/>
      <text x="${toScreenX(0) + 55 * Math.cos(angleRad / 2)}" y="${toScreenY(params.height) - 55 * Math.sin(angleRad / 2)}"
        fill="#fbbf24" font-size="11" font-family="monospace">${params.angle}°</text>

      <!-- Velocity arrow -->
      ${!state.landed && (Math.abs(state.velocity.x) > 0.1 || Math.abs(state.velocity.y) > 0.1) ? `
        <line x1="${ballX}" y1="${ballY}" x2="${vEndX}" y2="${vEndY}"
          stroke="#22c55e" stroke-width="2" marker-end="url(#arrowV)"/>
      ` : ''}

      <!-- Ball -->
      <circle cx="${ballX}" cy="${ballY}" r="8" fill="url(#ballGrad)" filter="url(#glow)"/>

      <!-- Axis labels -->
      <text x="${width / 2}" y="${height - 5}" text-anchor="middle" fill="#64748b" font-size="11" font-family="monospace">x (m)</text>
      <text x="12" y="${height / 2}" text-anchor="middle" fill="#64748b" font-size="11" font-family="monospace" transform="rotate(-90, 12, ${height / 2})">y (m)</text>

      <!-- Info -->
      <text x="${width - padding}" y="20" text-anchor="end" fill="#64748b" font-size="11" font-family="monospace">
        v₀ = ${params.initialVelocity} m/s  θ = ${params.angle}°
      </text>
    </svg>
  `
}

import type {
  SimType,
  SimState,
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  RealTimeValues,
} from './types'
import { createPendulumState, stepPendulum, getPendulumValues, createPendulumParams } from './pendulum'
import { createProjectileState, stepProjectile, getProjectileValues, createProjectileParams } from './projectile'
import { createSpringState, stepSpring, getSpringValues, createSpringParams } from './spring'

export type SimulationStore = {
  sim: SimState
  pendulum: { params: PendulumParams; state: PendulumState }
  projectile: { params: ProjectileParams; state: ProjectileState }
  spring: { params: SpringParams; state: SpringState }
}

export const createStore = (): SimulationStore => {
  const pendulumParams = createPendulumParams()
  const projectileParams = createProjectileParams()
  const springParams = createSpringParams()

  return {
    sim: {
      time: 0,
      running: false,
      speed: 1,
      activeTab: 'pendulum',
    },
    pendulum: { params: pendulumParams, state: createPendulumState(pendulumParams) },
    projectile: { params: projectileParams, state: createProjectileState(projectileParams) },
    spring: { params: springParams, state: createSpringState(springParams) },
  }
}

export const tick = (store: SimulationStore, dt: number): SimulationStore => {
  if (!store.sim.running) return store

  const adjustedDt = dt * store.sim.speed
  const newTime = store.sim.time + adjustedDt

  return {
    ...store,
    sim: { ...store.sim, time: newTime },
    pendulum: {
      ...store.pendulum,
      state: stepPendulum(store.pendulum.state, store.pendulum.params, adjustedDt),
    },
    projectile: {
      ...store.projectile,
      state: stepProjectile(store.projectile.state, store.projectile.params, adjustedDt),
    },
    spring: {
      ...store.spring,
      state: stepSpring(store.spring.state, store.spring.params, adjustedDt),
    },
  }
}

export const setActiveTab = (store: SimulationStore, tab: SimType): SimulationStore => ({
  ...store,
  sim: { ...store.sim, activeTab: tab },
})

export const toggleRunning = (store: SimulationStore): SimulationStore => ({
  ...store,
  sim: { ...store.sim, running: !store.sim.running },
})

export const setSpeed = (store: SimulationStore, speed: number): SimulationStore => ({
  ...store,
  sim: { ...store.sim, speed },
})

export const resetSim = (store: SimulationStore, tab?: SimType): SimulationStore => {
  const target = tab ?? store.sim.activeTab
  const next = { ...store, sim: { ...store.sim, time: 0, running: false } }

  if (target === 'pendulum' || !tab) {
    next.pendulum = { ...next.pendulum, state: createPendulumState(next.pendulum.params) }
  }
  if (target === 'projectile' || !tab) {
    next.projectile = { ...next.projectile, state: createProjectileState(next.projectile.params) }
  }
  if (target === 'spring' || !tab) {
    next.spring = { ...next.spring, state: createSpringState(next.spring.params) }
  }

  return next
}

export const updatePendulumParams = (
  store: SimulationStore,
  updates: Partial<PendulumParams>,
): SimulationStore => {
  const params = { ...store.pendulum.params, ...updates }
  return {
    ...store,
    pendulum: { params, state: createPendulumState(params) },
    sim: { ...store.sim, time: 0, running: false },
  }
}

export const updateProjectileParams = (
  store: SimulationStore,
  updates: Partial<ProjectileParams>,
): SimulationStore => {
  const params = { ...store.projectile.params, ...updates }
  return {
    ...store,
    projectile: { params, state: createProjectileState(params) },
    sim: { ...store.sim, time: 0, running: false },
  }
}

export const updateSpringParams = (
  store: SimulationStore,
  updates: Partial<SpringParams>,
): SimulationStore => {
  const params = { ...store.spring.params, ...updates }
  return {
    ...store,
    spring: { params, state: createSpringState(params) },
    sim: { ...store.sim, time: 0, running: false },
  }
}

export const getActiveValues = (store: SimulationStore): RealTimeValues => {
  switch (store.sim.activeTab) {
    case 'pendulum':
      return getPendulumValues(store.pendulum.state, store.pendulum.params)
    case 'projectile':
      return getProjectileValues(store.projectile.state, store.projectile.params)
    case 'spring':
      return getSpringValues(store.spring.state, store.spring.params)
  }
}

