import {
  createStore,
  tick,
  setActiveTab,
  toggleRunning,
  setSpeed,
  resetSim,
  updatePendulumParams,
  updateProjectileParams,
  updateSpringParams,
  getActiveValues,
} from './sim-engine'
import type { SimulationStore } from './sim-engine'
import type { SimType } from './types'
import { render } from './renderer'

const SIM_DT = 1 / 60

// --- State ---
let store: SimulationStore = createStore()
let animationTimer: ReturnType<typeof setInterval> | null = null

// --- Simulation loop ---
const startLoop = () => {
  if (animationTimer) return
  animationTimer = setInterval(() => {
    store = tick(store, SIM_DT)
  }, SIM_DT * 1000)
}

const stopLoop = () => {
  if (animationTimer) {
    clearInterval(animationTimer)
    animationTimer = null
  }
}

// --- Event handlers ---
type EventAction =
  | { type: 'tab'; tab: SimType }
  | { type: 'toggle-play' }
  | { type: 'reset' }
  | { type: 'speed'; speed: number }
  | { type: 'param-change'; param: string; value: number }

const dispatch = (action: EventAction): void => {
  switch (action.type) {
    case 'tab':
      stopLoop()
      store = setActiveTab(store, action.tab)
      store = resetSim(store, action.tab)
      break

    case 'toggle-play':
      store = toggleRunning(store)
      if (store.sim.running) {
        startLoop()
      } else {
        stopLoop()
      }
      break

    case 'reset':
      stopLoop()
      store = resetSim(store)
      break

    case 'speed':
      store = setSpeed(store, action.speed)
      break

    case 'param-change':
      stopLoop()
      applyParam(action.param, action.value)
      break
  }
}

const applyParam = (param: string, value: number): void => {
  switch (param) {
    case 'p-length':
      store = updatePendulumParams(store, { length: value })
      break
    case 'p-gravity':
      store = updatePendulumParams(store, { gravity: value })
      break
    case 'p-angle':
      store = updatePendulumParams(store, { initialAngle: value })
      break
    case 'pr-angle':
      store = updateProjectileParams(store, { angle: value })
      break
    case 'pr-velocity':
      store = updateProjectileParams(store, { initialVelocity: value })
      break
    case 'pr-gravity':
      store = updateProjectileParams(store, { gravity: value })
      break
    case 's-k':
      store = updateSpringParams(store, { springConstant: value })
      break
    case 's-mass':
      store = updateSpringParams(store, { mass: value })
      break
    case 's-disp':
      store = updateSpringParams(store, { initialDisplacement: value })
      break
  }
}

// --- HTTP Server ---
const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)

  if (req.method === 'GET' && url.pathname === '/') {
    const html = render(store)
    return new Response(wrapHtml(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (req.method === 'POST' && url.pathname === '/action') {
    const body = await req.json() as EventAction
    dispatch(body)
    return new Response(JSON.stringify({ ok: true }), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (req.method === 'GET' && url.pathname === '/state') {
    const values = getActiveValues(store)
    return new Response(JSON.stringify({
      time: store.sim.time,
      running: store.sim.running,
      speed: store.sim.speed,
      activeTab: store.sim.activeTab,
      values,
    }), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (req.method === 'GET' && url.pathname === '/render') {
    const html = render(store)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  return new Response('Not found', { status: 404 })
}

const wrapHtml = (body: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #0b1120; overflow-x: hidden; }
    input[type="range"] {
      -webkit-appearance: none;
      appearance: none;
      background: #1e293b;
      border-radius: 4px;
      outline: none;
    }
    input[type="range"]::-webkit-slider-thumb {
      -webkit-appearance: none;
      appearance: none;
      width: 14px;
      height: 14px;
      border-radius: 50%;
      background: #3b82f6;
      cursor: pointer;
    }
    button { outline: none; border: none; font-family: inherit; }
    button:hover { filter: brightness(1.15); }
    button:active { transform: scale(0.97); }
  </style>
</head>
<body>
  ${body}
  <script>
    const POLL_MS = 1000 / 30;

    const post = async (action) => {
      await fetch('/action', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(action),
      });
    };

    // Event delegation
    document.addEventListener('click', async (e) => {
      const btn = e.target.closest('[p-trigger]');
      if (!btn) return;
      const trigger = btn.getAttribute('p-trigger');
      if (!trigger) return;

      const [, action] = trigger.split(':');
      if (action === 'toggle-play') await post({ type: 'toggle-play' });
      else if (action === 'reset') await post({ type: 'reset' });
      else if (action.startsWith('tab-')) await post({ type: 'tab', tab: action.replace('tab-', '') });
      else if (action.startsWith('speed-')) await post({ type: 'speed', speed: parseFloat(action.replace('speed-', '')) });

      refreshUI();
    });

    document.addEventListener('change', async (e) => {
      const input = e.target.closest('[p-trigger]');
      if (!input) return;
      const param = input.getAttribute('data-param');
      if (!param) return;
      await post({ type: 'param-change', param, value: parseFloat(input.value) });
      refreshUI();
    });

    const refreshUI = async () => {
      const res = await fetch('/render');
      const html = await res.text();
      document.body.innerHTML = html;
    };

    // Poll for animation updates
    let polling = false;
    const poll = async () => {
      const res = await fetch('/state');
      const state = await res.json();
      if (state.running && !polling) {
        polling = true;
        const loop = async () => {
          if (!polling) return;
          await refreshUI();
          const s = await fetch('/state').then(r => r.json());
          if (!s.running) { polling = false; return; }
          requestAnimationFrame(loop);
        };
        requestAnimationFrame(loop);
      } else if (!state.running) {
        polling = false;
      }
    };

    // Check state periodically for external changes
    setInterval(poll, 500);
  </script>
</body>
</html>`

