export const buildTableGrid = (elements: Element[]) => {
  const grid: (Element | null)[][] = Array.from({ length: 10 }, () =>
    Array.from({ length: 18 }, () => null),
  )

  for (const el of elements) {
    grid[el.row - 1][el.col - 1] = el
  }

  const cells: ReturnType<typeof h>[] = []

  // Main table rows 1-7
  for (let row = 0; row < 7; row++) {
    for (let col = 0; col < 18; col++) {
      const el = grid[row][col]
      if (el) {
        cells.push(h('div', { style: styleStr({ gridRow: String(row + 1), gridColumn: String(col + 1) }) }, renderElementCell(el)))
      } else if (row === 5 && col === 2) {
        // Lanthanide pointer in row 6, col 3
        cells.push(h('div', {
          style: styleStr({
            gridRow: '6',
            gridColumn: '3',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '10px',
            color: '#f783ac',
            fontWeight: '600',
          }),
        }, '57-71 \u25BC'))
      } else if (row === 6 && col === 2) {
        // Actinide pointer in row 7, col 3
        cells.push(h('div', {
          style: styleStr({
            gridRow: '7',
            gridColumn: '3',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '10px',
            color: '#e599f7',
            fontWeight: '600',
          }),
        }, '89-103 \u25BC'))
      }
    }
  }

  // Separator row 8
  cells.push(h('div', { style: styleStr({ gridRow: '8', gridColumn: '1 / -1', height: '12px' }) }))

  // Lanthanides - row 9
  cells.push(h('div', {
    style: styleStr({
      gridRow: '9',
      gridColumn: '1 / 3',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontSize: '10px',
      color: '#f783ac',
      fontWeight: '600',
    }),
  }, 'Lanthanides'))
  for (let col = 2; col < 18; col++) {
    const el = grid[8][col]
    if (el) {
      cells.push(h('div', { style: styleStr({ gridRow: '9', gridColumn: String(col + 1) }) }, renderElementCell(el)))
    }
  }

  // Actinides - row 10
  cells.push(h('div', {
    style: styleStr({
      gridRow: '10',
      gridColumn: '1 / 3',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontSize: '10px',
      color: '#e599f7',
      fontWeight: '600',
    }),
  }, 'Actinides'))
  for (let col = 2; col < 18; col++) {
    const el = grid[9][col]
    if (el) {
      cells.push(h('div', { style: styleStr({ gridRow: '10', gridColumn: String(col + 1) }) }, renderElementCell(el)))
    }
  }

  return cells
}

export const renderPeriodicTable = (
  elements: Element[],
  selectedElement: Element | null = null,
) => {
  const gridCells = buildTableGrid(elements)

  return h(
    'div',
    { style: styleStr(s.container), 'p-target': 'tableRoot' },
    h(
      'div',
      { style: styleStr(s.header) },
      h('h1', { style: styleStr(s.title) }, 'Periodic Table of Elements'),
      renderSearchBar(),
    ),
    renderFilterButtons(),
    h(
      'div',
      {
        style: styleStr({ ...s.grid, gridTemplateRows: 'repeat(10, auto)' }),
        'p-target': 'tableGrid',
      },
      ...gridCells,
    ),
    ...(selectedElement ? [renderDetailPanel(selectedElement)] : []),
  )
}

