import type { Element, ElementCategory } from './types'
import { categories } from './categories'
import { renderPeriodicTable, renderDetailPanel, buildTableGrid } from './render'

const DATA_PATH = './data/elements.json'

const loadElements = async (): Promise<Element[]> => {
  const file = Bun.file(DATA_PATH)
  const data = await file.json()
  return data as Element[]
}

type AppState = {
  elements: Element[]
  filteredElements: Element[]
  selectedElement: Element | null
  activeCategory: ElementCategory | 'all'
  searchQuery: string
}

const createState = (elements: Element[]): AppState => ({
  elements,
  filteredElements: elements,
  selectedElement: null,
  activeCategory: 'all',
  searchQuery: '',
})

const applyFilters = (state: AppState): Element[] => {
  const { elements, activeCategory, searchQuery } = state
  const query = searchQuery.toLowerCase().trim()

  return elements.filter(el => {
    const matchesCategory = activeCategory === 'all' || el.category === activeCategory
    const matchesSearch =
      !query ||
      el.name.toLowerCase().includes(query) ||
      el.symbol.toLowerCase().includes(query) ||
      String(el.atomicNumber).includes(query)

    return matchesCategory && matchesSearch
  })
}

const selectElement = (state: AppState, atomicNumber: number): AppState => {
  const element = state.elements.find(el => el.atomicNumber === atomicNumber) ?? null
  return { ...state, selectedElement: element }
}

const closeDetail = (state: AppState): AppState => ({
  ...state,
  selectedElement: null,
})

const filterByCategory = (state: AppState, category: ElementCategory | 'all'): AppState => {
  const newState = { ...state, activeCategory: category }
  return { ...newState, filteredElements: applyFilters(newState) }
}

const search = (state: AppState, query: string): AppState => {
  const newState = { ...state, searchQuery: query }
  return { ...newState, filteredElements: applyFilters(newState) }
}

const renderApp = (state: AppState): string => {
  const template = renderPeriodicTable(state.filteredElements, state.selectedElement)
  return String(template)
}

