      if (queryParam) {
        state = search(state, queryParam)
      }

      const selectParam = url.searchParams.get('select')
      if (selectParam) {
        state = selectElement(state, parseInt(selectParam, 10))
      }

      const pageHtml = `<!DOCTYPE html>
