          } else {
            search.delete('q');
          }
          search.delete('select');
          window.location.href = '/?' + search.toString();
        }, 300);
      }
    });

    // Restore search input value from URL
    const params = new URLSearchParams(window.location.search);
    const qVal = params.get('q');
    if (qVal) {
      const input = document.querySelector('[p-target="searchInput"]');
      if (input) input.value = qVal;
    }

    // Mark active/inactive filter buttons
