/** Parse a string of comma-separated numbers or a JSON array into number[] */
export const parseDataset = (input: string): number[] => {
  const trimmed = input.trim()
  if (trimmed.startsWith('[')) {
    const parsed: unknown = JSON.parse(trimmed)
    if (!Array.isArray(parsed)) throw new Error('Input is not a JSON array')
    return parsed.map((v, i) => {
      const n = Number(v)
      if (Number.isNaN(n)) throw new Error(`Non-numeric value at index ${i}: ${v}`)
      return n
    })
  }
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map((s, i) => {
      const n = Number(s)
      if (Number.isNaN(n)) throw new Error(`Non-numeric value at position ${i + 1}: "${s}"`)
      return n
    })
}

export type Stats = {
  count: number
  mean: number
  median: number
  mode: number[]
  stdDev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sorted = (data: number[]): number[] => [...data].sort((a, b) => a - b)

const quantile = (sortedData: number[], q: number): number => {
  const pos = (sortedData.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sortedData[lo]
  return sortedData[lo] + (sortedData[hi] - sortedData[lo]) * (pos - lo)
}

export const computeStats = (data: number[]): Stats => {
  if (data.length === 0) throw new Error('Dataset must not be empty')
  const s = sorted(data)
  const count = s.length
  const mean = s.reduce((a, b) => a + b, 0) / count
  const median = quantile(s, 0.5)
  const variance = s.reduce((sum, v) => sum + (v - mean) ** 2, 0) / count
  const stdDev = Math.sqrt(variance)
  const min = s[0]
  const max = s[count - 1]
  const range = max - min
  const q1 = quantile(s, 0.25)
  const q3 = quantile(s, 0.75)
  const iqr = q3 - q1

  // mode: values with highest frequency
  const freq = new Map<number, number>()
  for (const v of s) freq.set(v, (freq.get(v) ?? 0) + 1)
  const maxFreq = Math.max(...freq.values())
  const mode = maxFreq === 1 ? [] : [...freq.entries()].filter(([, f]) => f === maxFreq).map(([v]) => v)

  return { count, mean, median, mode, stdDev, variance, min, max, range, q1, q3, iqr }
}

export const fmt = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  return n.toFixed(4).replace(/0+$/, '').replace(/\.$/, '')
}

