// ─── Colors ──────────────────────────────────────────────────────────

const PALETTE = ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7']

const colorFor = (i: number): string => PALETTE[i % PALETTE.length]

// ─── Summary Table ───────────────────────────────────────────────────

const STAT_KEYS: { key: keyof Stats; label: string }[] = [
  { key: 'count', label: 'Count' },
  { key: 'mean', label: 'Mean' },
  { key: 'median', label: 'Median' },
  { key: 'mode', label: 'Mode' },
  { key: 'stdDev', label: 'Std Dev' },
  { key: 'variance', label: 'Variance' },
  { key: 'min', label: 'Min' },
  { key: 'max', label: 'Max' },
  { key: 'range', label: 'Range' },
  { key: 'q1', label: 'Q1' },
  { key: 'q3', label: 'Q3' },
  { key: 'iqr', label: 'IQR' },
]

const fmtCell = (stats: Stats, key: keyof Stats): string => {
  const v = stats[key]
  if (key === 'mode') return (v as number[]).length === 0 ? 'none' : (v as number[]).map(fmt).join(', ')
  return fmt(v as number)
}

export const renderSummaryTable = (datasets: NamedDataset[]): string => {
  const thStyle = 'padding:6px 12px;text-align:left;border-bottom:2px solid #555;background:#1e1e2e;color:#cdd6f4;'
  const tdStyle = 'padding:6px 12px;border-bottom:1px solid #333;color:#cdd6f4;'
  const headerRow = h(
    'tr',
    {},
    h('th', { style: thStyle }, 'Statistic'),
    ...datasets.map((ds, i) => h('th', { style: `${thStyle}color:${colorFor(i)};` }, ds.name)),
  )
  const bodyRows = STAT_KEYS.map(({ key, label }) =>
    h(
      'tr',
      {},
      h('td', { style: `${tdStyle}font-weight:600;` }, label),
