    ),
  )
  return h(
    'table',
    { style: 'border-collapse:collapse;width:100%;font-family:monospace;font-size:14px;margin:16px 0;' },
    h('thead', {}, headerRow),
    h('tbody', {}, ...bodyRows),
  )
}

// ─── SVG Box Plot ────────────────────────────────────────────────────

export const renderBoxPlot = (datasets: NamedDataset[]): string => {
  const plotW = 600
  const plotH = 60 * datasets.length + 40
  const marginL = 100
  const marginR = 20
  const marginT = 20
  const marginB = 30
  const innerW = plotW - marginL - marginR
  const boxH = 30

  const globalMin = Math.min(...datasets.map((d) => d.stats.min))
  const globalMax = Math.max(...datasets.map((d) => d.stats.max))
  const pad = (globalMax - globalMin) * 0.05 || 1
  const lo = globalMin - pad
  const hi = globalMax + pad

  const x = (v: number) => marginL + ((v - lo) / (hi - lo)) * innerW

  // Tick marks
  const tickCount = 6
  const ticks: number[] = []
  for (let i = 0; i <= tickCount; i++) ticks.push(lo + (i / tickCount) * (hi - lo))

  const tickEls = ticks.map((t) =>
    h('g', {},
      h('line', { x1: String(x(t)), x2: String(x(t)), y1: String(marginT), y2: String(plotH - marginB), stroke: '#444', 'stroke-dasharray': '3,3' }),
      h('text', { x: String(x(t)), y: String(plotH - 8), fill: '#999', 'font-size': '11', 'text-anchor': 'middle' }, fmt(t)),
    ),
  )

  const boxEls = datasets.map((ds, i) => {
    const cy = marginT + i * 60 + 30
    const y0 = cy - boxH / 2
    const s = ds.stats
    const whiskerLo = Math.max(s.min, s.q1 - 1.5 * s.iqr)
    const whiskerHi = Math.min(s.max, s.q3 + 1.5 * s.iqr)
    const outliers = ds.data.filter((v) => v < whiskerLo || v > whiskerHi)
    const color = colorFor(i)

    return h('g', {},
      // label
      h('text', { x: String(marginL - 8), y: String(cy + 4), fill: color, 'font-size': '13', 'text-anchor': 'end', 'font-weight': '600' }, ds.name),
      // whisker line
      h('line', { x1: String(x(whiskerLo)), x2: String(x(whiskerHi)), y1: String(cy), y2: String(cy), stroke: color, 'stroke-width': '1.5' }),
      // whisker caps
      h('line', { x1: String(x(whiskerLo)), x2: String(x(whiskerLo)), y1: String(y0 + 5), y2: String(y0 + boxH - 5), stroke: color, 'stroke-width': '1.5' }),
      h('line', { x1: String(x(whiskerHi)), x2: String(x(whiskerHi)), y1: String(y0 + 5), y2: String(y0 + boxH - 5), stroke: color, 'stroke-width': '1.5' }),
      // box (Q1 to Q3)
      h('rect', { x: String(x(s.q1)), y: String(y0), width: String(x(s.q3) - x(s.q1)), height: String(boxH), fill: color, 'fill-opacity': '0.25', stroke: color, 'stroke-width': '1.5', rx: '3' }),
      // median line
      h('line', { x1: String(x(s.median)), x2: String(x(s.median)), y1: String(y0), y2: String(y0 + boxH), stroke: color, 'stroke-width': '2.5' }),
      // outliers
      ...outliers.map((v) => h('circle', { cx: String(x(v)), cy: String(cy), r: '3.5', fill: 'none', stroke: color, 'stroke-width': '1.5' })),
    )
  })

  return h(
    'div',
    { style: 'margin:16px 0;' },
    h('h3', { style: 'color:#cdd6f4;margin-bottom:8px;font-size:15px;' }, 'Box Plot'),
    h('svg', { viewBox: `0 0 ${plotW} ${plotH}`, width: String(plotW), style: 'background:#181825;border-radius:8px;' },
      ...tickEls,
      ...boxEls,
    ),
  )
}

// ─── SVG Histogram ───────────────────────────────────────────────────

export const renderHistogram = (datasets: NamedDataset[]): string => {
  const plotW = 600
  const plotH = 300
  const marginL = 50
  const marginR = 20
  const marginT = 20
  const marginB = 40
  const innerW = plotW - marginL - marginR
  const innerH = plotH - marginT - marginB

  const globalMin = Math.min(...datasets.map((d) => d.stats.min))
  const globalMax = Math.max(...datasets.map((d) => d.stats.max))
  const pad = (globalMax - globalMin) * 0.05 || 1
  const lo = globalMin - pad
  const hi = globalMax + pad

  // Sturges' rule for bin count
  const maxCount = Math.max(...datasets.map((d) => d.data.length))
  const binCount = Math.max(5, Math.ceil(1 + 3.322 * Math.log10(maxCount)))
  const binWidth = (hi - lo) / binCount

  // Build frequency bins per dataset
  const allBins: number[][] = datasets.map((ds) => {
    const bins = new Array<number>(binCount).fill(0)
    for (const v of ds.data) {
      let idx = Math.floor((v - lo) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx]++
    }
    return bins
  })

  const maxFreq = Math.max(...allBins.flat())
  const x = (v: number) => marginL + ((v - lo) / (hi - lo)) * innerW
  const y = (f: number) => marginT + innerH - (f / (maxFreq || 1)) * innerH

  // X axis ticks
  const xTickCount = Math.min(binCount + 1, 10)
  const xTicks: number[] = []
  for (let i = 0; i <= xTickCount; i++) xTicks.push(lo + (i / xTickCount) * (hi - lo))

  // Y axis ticks
  const yTickCount = 5
  const yTicks: number[] = []
  for (let i = 0; i <= yTickCount; i++) yTicks.push(Math.round((i / yTickCount) * maxFreq))

  const barGroupWidth = binWidth / datasets.length

  const barEls = datasets.flatMap((ds, di) =>
    allBins[di].map((freq, bi) => {
      if (freq === 0) return ''
      const bx = x(lo + bi * binWidth + di * barGroupWidth)
      const bw = Math.max(1, x(lo + barGroupWidth) - x(lo) - 1)
      const by = y(freq)
      const bh = y(0) - by
      return h('rect', { x: String(bx), y: String(by), width: String(bw), height: String(bh), fill: colorFor(di), 'fill-opacity': '0.6', rx: '1' })
    }),
  )

  const xTickEls = xTicks.map((t) =>
    h('text', { x: String(x(t)), y: String(plotH - 8), fill: '#999', 'font-size': '11', 'text-anchor': 'middle' }, fmt(t)),
  )

  const yTickEls = yTicks.map((t) =>
    h('g', {},
      h('line', { x1: String(marginL), x2: String(plotW - marginR), y1: String(y(t)), y2: String(y(t)), stroke: '#333', 'stroke-dasharray': '3,3' }),
      h('text', { x: String(marginL - 8), y: String(y(t) + 4), fill: '#999', 'font-size': '11', 'text-anchor': 'end' }, String(t)),
    ),
  )

  // Legend
  const legendEls = datasets.map((ds, i) =>
    h('g', { transform: `translate(${marginL + i * 120}, ${plotH - 2})` },
      h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colorFor(i), 'fill-opacity': '0.7', rx: '2' }),
      h('text', { x: '16', y: '2', fill: '#cdd6f4', 'font-size': '12' }, ds.name),
    ),
  )

  return h(
    'div',
    { style: 'margin:16px 0;' },
    h('h3', { style: 'color:#cdd6f4;margin-bottom:8px;font-size:15px;' }, 'Histogram'),
    h('svg', { viewBox: `0 0 ${plotW} ${plotH}`, width: String(plotW), style: 'background:#181825;border-radius:8px;' },
      ...yTickEls,
      ...barEls,
      ...xTickEls,
      ...legendEls,
    ),
  )
}

