export const renderPage = (datasets: NamedDataset[]): string => {
  if (datasets.length === 0) {
    return h('div', { style: 'color:#999;padding:32px;font-family:sans-serif;' }, 'No datasets loaded. Add a dataset to begin.')
  }
  return h(
    'div',
    { style: 'font-family:system-ui,sans-serif;max-width:700px;margin:0 auto;padding:16px;' },
    renderSummaryTable(datasets),
    renderBoxPlot(datasets),
    renderHistogram(datasets),
  )
}

import { parseDataset } from './parse.js'
import { computeStats } from './stats.js'
import { type NamedDataset, renderPage } from './render.js'

const DATA_PATH = './data/datasets.json'

type StoredDataset = { name: string; data: number[] }

// ─── Persistence ─────────────────────────────────────────────────────

const loadDatasets = async (): Promise<StoredDataset[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json() as Promise<StoredDataset[]>
}

const saveDatasets = async (datasets: StoredDataset[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(datasets, null, 2))
}

// ─── Actions ─────────────────────────────────────────────────────────

export const addDataset = async (name: string, input: string): Promise<NamedDataset[]> => {
  const data = parseDataset(input)
  if (data.length === 0) throw new Error('Dataset is empty after parsing')
  const stored = await loadDatasets()
  const existing = stored.findIndex((d) => d.name === name)
  if (existing >= 0) {
    stored[existing] = { name, data }
  } else {
    stored.push({ name, data })
  }
  await saveDatasets(stored)
  return toNamed(stored)
}

export const removeDataset = async (name: string): Promise<NamedDataset[]> => {
  const stored = await loadDatasets()
  const filtered = stored.filter((d) => d.name !== name)
  await saveDatasets(filtered)
  return toNamed(filtered)
}

export const listDatasets = async (): Promise<NamedDataset[]> => {
  const stored = await loadDatasets()
  return toNamed(stored)
}

const toNamed = (stored: StoredDataset[]): NamedDataset[] =>
  stored.map((d) => ({ name: d.name, data: d.data, stats: computeStats(d.data) }))

// ─── Render ──────────────────────────────────────────────────────────

export const render = async (): Promise<string> => {
  const datasets = await listDatasets()
  return renderPage(datasets)
}

// ─── CLI entry point ─────────────────────────────────────────────────

const main = async () => {
  const [command, ...args] = process.argv.slice(2)

  if (command === 'add' && args.length >= 2) {
    const name = args[0]
    const input = args.slice(1).join(' ')
    const datasets = await addDataset(name, input)
    console.log(`Added dataset "${name}" (${datasets.find((d) => d.name === name)!.data.length} values)`)
    console.log(renderPage(datasets))
  } else if (command === 'remove' && args.length === 1) {
    const datasets = await removeDataset(args[0])
    console.log(`Removed dataset "${args[0]}"`)
    console.log(renderPage(datasets))
  } else if (command === 'view') {
    const html = await render()
    console.log(html)
  } else {
    console.log('Usage:')
    console.log('  bun run src/index.ts add <name> <values>   Add/update a dataset')
    console.log('  bun run src/index.ts remove <name>         Remove a dataset')
    console.log('  bun run src/index.ts view                  Render all datasets')
    console.log('')
    console.log('Values can be comma-separated or a JSON array:')
    console.log('  bun run src/index.ts add scores 85, 90, 78, 92, 88')
    console.log('  bun run src/index.ts add temps "[72, 68, 75, 80, 71]"')
  }
}

main().catch((err: Error) => {
  console.error(`Error: ${err.message}`)
  process.exit(1)
})
